const CACHE_NAME = 'ponkhiraj-v1';
const ASSETS_TO_CACHE = [
  './',
  './index.html',
  './manifest.json'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS_TO_CACHE);
    })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

{
  "name": "Caption PTT",
  "description": "A comprehensive tour management application for Caption PTT featuring automated caption generation using Gemini AI, admin/moderator roles, and host settlement analysis.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export enum UserRole {
  GUEST = 'guest',
  MODERATOR = 'moderator',
  ADMIN = 'admin'
}

export interface User {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  isApproved: boolean;
  createdAt: string;
}

export interface Tour {
  id: string;
  name: string;
  driveLink: string;
  description: string;
  price: string;
  bookingNumber: string;
  imageUrl: string;
  createdAt: string;
}

export interface Guest {
  id: string;
  tourId: string;
  name: string;
  phone: string;
  totalBill: number;
  collected: number;
  type: 'agency' | 'personal';
  status: 'pending' | 'received';
  createdAt: string;
}

export interface AppState {
  currentUser: User | null;
  tours: Tour[];
  users: User[];
  guests: Guest[];
  isAuthLoading: boolean;
}

import React, { useState, useEffect } from 'react';
import { User, Tour, UserRole, Guest } from './types';
import Layout from './components/Layout';
import TourCard from './components/TourCard';
import TourDetail from './components/TourDetail';
import AdminPanel from './components/AdminPanel';
import Login from './components/Login';
import { Sparkles, Map, ArrowDownCircle, Plane } from 'lucide-react';

// Firebase imports
import { auth, db } from './firebase';
import { onAuthStateChanged, signOut, signInWithEmailAndPassword, createUserWithEmailAndPassword } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { collection, onSnapshot, doc, getDoc, setDoc, updateDoc, deleteDoc, query, orderBy } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

const App: React.FC = () => {
  const [tours, setTours] = useState<Tour[]>(() => {
    const saved = localStorage.getItem('ponkhiraj_tours');
    return saved ? JSON.parse(saved) : [];
  });

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('ponkhiraj_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [users, setUsers] = useState<User[]>([]);
  const [guests, setGuests] = useState<Guest[]>([]);
  const [loading, setLoading] = useState(!currentUser);
  const [view, setView] = useState<'home' | 'admin' | 'login' | 'detail'>('home');
  const [selectedTour, setSelectedTour] = useState<Tour | null>(null);

  useEffect(() => {
    localStorage.setItem('ponkhiraj_tours', JSON.stringify(tours));
  }, [tours]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('ponkhiraj_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('ponkhiraj_user');
    }
  }, [currentUser]);

  useEffect(() => {
    let userUnsubscribe: (() => void) | null = null;

    const authUnsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (userUnsubscribe) {
        userUnsubscribe();
        userUnsubscribe = null;
      }

      if (firebaseUser) {
        const userRef = doc(db, "users", firebaseUser.uid);
        userUnsubscribe = onSnapshot(userRef, (userDoc) => {
          if (userDoc.exists()) {
            const userData = userDoc.data() as User;
            if (userData.isApproved) {
              setCurrentUser(userData);
            } else {
              setCurrentUser(null);
            }
          } else {
            setCurrentUser(null);
          }
          setLoading(false);
        }, (error) => {
          console.error("User sync error:", error);
          setLoading(false);
        });
      } else {
        setCurrentUser(null);
        setLoading(false);
      }
    });

    return () => {
      authUnsubscribe();
      if (userUnsubscribe) userUnsubscribe();
    };
  }, []);

  useEffect(() => {
    const q = query(collection(db, "tours"), orderBy("createdAt", "desc"));
    return onSnapshot(q, (snapshot) => {
      const fetchedTours = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Tour));
      setTours(fetchedTours);
    });
  }, []);

  useEffect(() => {
    if (currentUser?.role === UserRole.ADMIN || currentUser?.role === UserRole.MODERATOR) {
      const guestsUnsub = onSnapshot(collection(db, "guests"), (snapshot) => {
        setGuests(snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Guest)));
      });

      let usersUnsub: (() => void) | undefined;
      if (currentUser?.role === UserRole.ADMIN) {
        usersUnsub = onSnapshot(collection(db, "users"), (snapshot) => {
          setUsers(snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as User)));
        });
      }

      return () => {
        guestsUnsub();
        if (usersUnsub) usersUnsub();
      };
    }
  }, [currentUser]);

  const handleLogin = async (email: string, pass: string) => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, pass);
      const userDoc = await getDoc(doc(db, "users", userCredential.user.uid));
      if (userDoc.exists() && (userDoc.data() as User).isApproved) {
        const userData = userDoc.data() as User;
        setCurrentUser(userData);
        setView('home');
        return true;
      }
      return false;
    } catch { return false; }
  };

  const handleRegister = async (name: string, email: string, pass: string) => {
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, pass);
      await setDoc(doc(db, "users", cred.user.uid), {
        id: cred.user.uid, name, email, role: UserRole.GUEST, isApproved: false, createdAt: new Date().toISOString()
      });
      await signOut(auth);
      return true;
    } catch (e: any) {
      return e.code === 'auth/email-already-in-use' ? 'email-in-use' : false;
    }
  };

  const handleLogout = async () => {
    await signOut(auth);
    setCurrentUser(null);
    setView('home');
    setSelectedTour(null);
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#f8fafc]">
        <div className="flex flex-col items-center gap-8 animate-fade-in">
          <div className="relative">
            <div className="w-24 h-24 bg-white rounded-3xl overflow-hidden shadow-2xl flex items-center justify-center animate-pulse border border-slate-100">
              <img src="https://i.postimg.cc/xj3Bb7TR/Untitled_design.png" alt="Logo" className="w-20 h-20 object-cover" />
            </div>
          </div>
          <p className="text-slate-900 font-[900] tracking-[0.3em] uppercase text-xs">Caption PTT রেডি হচ্ছে</p>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} currentView={view}
      onNavigate={(v) => { setView(v); window.scrollTo({ top: 0, behavior: 'smooth' }); }}>

      {view === 'home' && (
        <div className="space-y-16 md:space-y-32">
          {/* Hero Section */}
          <section className="relative text-center space-y-12 py-10 md:py-20 animate-fade-in">
            <div className="inline-flex items-center gap-3 bg-white px-5 py-2.5 rounded-full shadow-lg border border-slate-50 mx-auto">
              <span className="relative flex h-3 w-3">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-3 w-3 bg-indigo-600"></span>
              </span>
              <span className="text-[10px] md:text-[12px] font-black text-slate-800 uppercase tracking-[0.2em]">Premium Travel Experience</span>
            </div>

            <div className="space-y-6">
              <h2 className="text-5xl sm:text-7xl md:text-[10rem] font-[1000] text-slate-900 tracking-tighter leading-[0.85] px-2">
                গন্তব্য হোক <br /> 
                <span className="text-gradient">সীমাহীন</span>
              </h2>
              <p className="text-slate-500 max-w-2xl mx-auto text-lg md:text-2xl font-medium leading-relaxed bengali-text px-6">
                Caption PTT এর সাথে আপনার প্রতিটি যাত্রা হবে আরামদায়ক এবং নিরাপদ। বাংলার প্রতিটি প্রান্তে আমাদের অভিজ্ঞ গাইডরা আছে আপনার অপেক্ষায়।
              </p>
            </div>

            <div className="pt-8 flex justify-center">
               <button 
                onClick={() => window.scrollTo({ top: window.innerHeight * 0.8, behavior: 'smooth' })} 
                className="group flex flex-col items-center gap-4 text-slate-300 hover:text-indigo-600 transition-all duration-500"
              >
                 <span className="text-[10px] font-black uppercase tracking-[0.3em]">নিচে দেখুন</span>
                 <ArrowDownCircle size={48} strokeWidth={1} className="animate-bounce" />
               </button>
            </div>
          </section>

          {/* Tours Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8 md:gap-12">
            {tours.map((tour, idx) => (
              <div 
                key={tour.id} 
                className="animate-fade-in" 
                style={{ animationDelay: `${idx * 150}ms` }}
              >
                <TourCard tour={tour} onClick={(t) => { setSelectedTour(t); setView('detail'); window.scrollTo(0,0); }} />
              </div>
            ))}
          </div>

          {tours.length === 0 && (
            <div className="text-center py-40 bg-white rounded-[4rem] border border-slate-100 shadow-xl mx-4 animate-fade-in">
              <div className="w-24 h-24 bg-slate-50 rounded-3xl flex items-center justify-center mx-auto mb-8 shadow-inner">
                <Map size={48} className="text-slate-200" />
              </div>
              <p className="text-slate-900 font-black text-2xl tracking-tight">বর্তমানে কোনো প্যাকেজ নেই</p>
              <p className="text-slate-400 text-sm mt-4 font-medium px-8">খুব শীঘ্রই আমাদের নতুন আকর্ষণীয় সব প্যাকেজ আসছে!</p>
            </div>
          )}
        </div>
      )}

      {view === 'detail' && selectedTour && (
        <TourDetail tour={selectedTour} user={currentUser} onBack={() => setView('home')} />
      )}

      {view === 'login' && (
        <Login onLogin={handleLogin} onRegister={handleRegister} />
      )}

      {view === 'admin' && (currentUser?.role === UserRole.ADMIN || currentUser?.role === UserRole.MODERATOR) && (
        <AdminPanel 
          tours={tours} 
          users={users.filter(u => u.id !== currentUser.id)} 
          guests={guests}
          onAddTour={async (t) => { const id = Math.random().toString(36).substr(2,9); await setDoc(doc(db,"tours",id),{...t,id,createdAt:new Date().toISOString()}); }}
          onUpdateTour={async (t) => { await updateDoc(doc(db,"tours",t.id),{...t}); }}
          onDeleteTour={async (id) => { if(confirm('আপনি কি এই ট্যুরটি ডিলিট করতে চান?')) await deleteDoc(doc(db,"tours",id)); }}
          onApproveUser={async (id, role) => { await updateDoc(doc(db,"users",id),{isApproved:true,role}); }}
          onDeleteUser={async (id) => { if(confirm('আপনি কি এই মেম্বারকে ডিলিট করতে চান?')) await deleteDoc(doc(db,"users",id)); }}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Tour, User, UserRole, Guest } from '../types';
import { Plus, Edit, Trash2, Users, LayoutGrid, PieChart, TrendingUp, DollarSign, Briefcase, UserCheck, AlertCircle } from 'lucide-react';
import { doc, setDoc, updateDoc, deleteDoc } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";
import { db } from '../firebase';

interface AdminPanelProps {
  tours: Tour[];
  users: User[];
  guests: Guest[];
  onAddTour: (tour: Omit<Tour, 'id' | 'createdAt'>) => void;
  onUpdateTour: (tour: Tour) => void;
  onDeleteTour: (id: string) => void;
  onApproveUser: (userId: string, role: UserRole) => void;
  onDeleteUser: (userId: string) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ tours, users, guests, onAddTour, onUpdateTour, onDeleteTour, onApproveUser, onDeleteUser }) => {
  const [activeTab, setActiveTab] = useState<'tours' | 'users' | 'guests' | 'analysis'>('tours');
  const [isAddingTour, setIsAddingTour] = useState(false);
  const [editingTour, setEditingTour] = useState<Tour | null>(null);
  const [isAddingGuest, setIsAddingGuest] = useState(false);
  const [selectedTourForGuests, setSelectedTourForGuests] = useState<string>('');

  const [tourFormData, setTourFormData] = useState({
    name: '', driveLink: '', description: '', price: '', bookingNumber: '', imageUrl: ''
  });

  const [guestFormData, setGuestFormData] = useState({
    name: '', phone: '', tourId: '', totalBill: 0, collected: 0, type: 'personal' as 'personal' | 'agency'
  });

  // Host Settlement Logic
  const analysisData = useMemo(() => {
    const tourStats = tours.map(tour => {
      const tourGuests = guests.filter(g => g.tourId === tour.id);
      const agencyCollection = tourGuests.filter(g => g.type === 'agency' && g.status === 'received').reduce((acc, g) => acc + g.collected, 0);
      const personalCollection = tourGuests.filter(g => g.type === 'personal' && g.status === 'received').reduce((acc, g) => acc + g.collected, 0);
      const totalCollection = agencyCollection + personalCollection;

      const totalBill = tourGuests.reduce((acc, g) => acc + g.totalBill, 0);
      const totalDue = totalBill - tourGuests.reduce((acc, g) => acc + g.collected, 0);

      return {
        id: tour.id,
        name: tour.name,
        agencyCollection,
        personalCollection,
        totalCollection,
        totalDue
      };
    });

    const overallCollection = tourStats.reduce((acc, s) => acc + s.totalCollection, 0);
    const overallDue = tourStats.reduce((acc, s) => acc + s.totalDue, 0);

    return { tourStats, overallCollection, overallDue };
  }, [tours, guests]);

  const handleTourSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTour) onUpdateTour({ ...editingTour, ...tourFormData });
    else onAddTour(tourFormData);
    setTourFormData({ name: '', driveLink: '', description: '', price: '', bookingNumber: '', imageUrl: '' });
    setIsAddingTour(false);
    setEditingTour(null);
  };

  const handleGuestSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const id = Math.random().toString(36).substr(2, 9);
    await setDoc(doc(db, "guests", id), {
      ...guestFormData,
      id,
      status: 'pending',
      createdAt: new Date().toISOString()
    });
    setGuestFormData({ name: '', phone: '', tourId: '', totalBill: 0, collected: 0, type: 'personal' });
    setIsAddingGuest(false);
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in slide-in-from-left-4 duration-500 pb-10 px-2 sm:px-0">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl md:text-3xl font-[900] text-slate-900 tracking-tight">ম্যানেজমেন্ট হাব</h2>
          <p className="text-slate-400 text-sm font-medium">আপনার ট্যুর এবং টিম নিয়ন্ত্রণ করুন</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl w-full sm:w-auto overflow-x-auto no-scrollbar">
          <button onClick={() => setActiveTab('tours')} className={`shrink-0 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'tours' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
            <LayoutGrid size={16} /> ট্যুর
          </button>
          <button onClick={() => setActiveTab('guests')} className={`shrink-0 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'guests' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
            <UserCheck size={16} /> গেস্ট
          </button>
          <button onClick={() => setActiveTab('analysis')} className={`shrink-0 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'analysis' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
            <PieChart size={16} /> অ্যানালাইসিস
          </button>
          <button onClick={() => setActiveTab('users')} className={`shrink-0 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
            <Users size={16} /> টিম
          </button>
        </div>
      </div>

      {activeTab === 'tours' && (
        <div className="space-y-6">
          <div className="flex justify-end">
            {!isAddingTour && (
              <button onClick={() => setIsAddingTour(true)} className="flex items-center gap-2 btn-gradient text-white px-6 py-3.5 rounded-2xl font-black text-xs shadow-lg w-full sm:w-auto justify-center">
                <Plus size={18} /> নতুন ট্যুর যোগ করুন
              </button>
            )}
          </div>
          {isAddingTour && (
             <div className="bg-white rounded-[2rem] p-6 md:p-10 shadow-2xl border border-slate-50">
               <h3 className="text-xl font-black text-slate-900 mb-8">{editingTour ? 'ট্যুর এডিট করুন' : 'নতুন ট্যুর প্যাকেজ'}</h3>
               <form onSubmit={handleTourSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <input required value={tourFormData.name} onChange={(e) => setTourFormData({...tourFormData, name: e.target.value})} placeholder="ট্যুরের নাম" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" />
                 <input required value={tourFormData.driveLink} onChange={(e) => setTourFormData({...tourFormData, driveLink: e.target.value})} placeholder="ড্রাইভ লিঙ্ক" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" />
                 <input required value={tourFormData.price} onChange={(e) => setTourFormData({...tourFormData, price: e.target.value})} placeholder="প্যাকেজ মূল্য (৳)" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" />
                 <input required value={tourFormData.bookingNumber} onChange={(e) => setTourFormData({...tourFormData, bookingNumber: e.target.value})} placeholder="বুকিং নম্বর" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" />
                 <div className="md:col-span-2"><input value={tourFormData.imageUrl} onChange={(e) => setTourFormData({...tourFormData, imageUrl: e.target.value})} placeholder="ছবির ইউআরএল" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" /></div>
                 <div className="md:col-span-2"><textarea required rows={4} value={tourFormData.description} onChange={(e) => setTourFormData({...tourFormData, description: e.target.value})} placeholder="বিস্তারিত বর্ণনা..." className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none"></textarea></div>
                 <div className="flex flex-col sm:flex-row gap-3 md:col-span-2">
                   <button type="submit" className="flex-1 btn-gradient text-white py-4 rounded-xl font-black text-xs">সেভ করুন</button>
                   <button type="button" onClick={() => setIsAddingTour(false)} className="px-8 py-4 bg-slate-100 text-slate-500 rounded-xl font-black text-xs">বাতিল</button>
                 </div>
               </form>
             </div>
          )}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {tours.map(t => (
              <div key={t.id} className="bg-white p-6 rounded-2xl border border-slate-50 shadow-sm">
                <div className="flex items-center justify-between mb-2">
                  <h4 className="font-black text-slate-900">{t.name}</h4>
                  <div className="flex gap-1">
                    <button onClick={() => { setEditingTour(t); setTourFormData(t); setIsAddingTour(true); }} className="p-2 text-slate-400 hover:text-indigo-600"><Edit size={16} /></button>
                    <button onClick={() => onDeleteTour(t.id)} className="p-2 text-slate-400 hover:text-rose-600"><Trash2 size={16} /></button>
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">৳{t.price}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'guests' && (
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <select value={selectedTourForGuests} onChange={(e) => setSelectedTourForGuests(e.target.value)} className="bg-white border border-slate-200 px-4 py-2.5 rounded-xl font-black text-xs outline-none">
              <option value="">সব ট্যুর</option>
              {tours.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
            </select>
            <button onClick={() => setIsAddingGuest(true)} className="btn-gradient text-white px-6 py-3.5 rounded-2xl font-black text-xs">
              <Plus size={18} className="inline mr-2" /> গেস্ট যোগ করুন
            </button>
          </div>

          {isAddingGuest && (
            <div className="bg-white rounded-[2rem] p-6 shadow-xl border border-slate-50">
              <h3 className="text-lg font-black text-slate-900 mb-6">গেস্ট ইনফরমেশন</h3>
              <form onSubmit={handleGuestSubmit} className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <input required value={guestFormData.name} onChange={(e) => setGuestFormData({...guestFormData, name: e.target.value})} placeholder="নাম" className="bg-slate-50 px-4 py-3 rounded-lg text-sm font-bold" />
                <input required value={guestFormData.phone} onChange={(e) => setGuestFormData({...guestFormData, phone: e.target.value})} placeholder="ফোন" className="bg-slate-50 px-4 py-3 rounded-lg text-sm font-bold" />
                <select required value={guestFormData.tourId} onChange={(e) => setGuestFormData({...guestFormData, tourId: e.target.value})} className="bg-slate-50 px-4 py-3 rounded-lg text-sm font-bold">
                  <option value="">ট্যুর সিলেক্ট করুন</option>
                  {tours.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                </select>
                <input required type="number" value={guestFormData.totalBill} onChange={(e) => setGuestFormData({...guestFormData, totalBill: parseInt(e.target.value)})} placeholder="মোট বিল" className="bg-slate-50 px-4 py-3 rounded-lg text-sm font-bold" />
                <input required type="number" value={guestFormData.collected} onChange={(e) => setGuestFormData({...guestFormData, collected: parseInt(e.target.value)})} placeholder="সংগৃহীত টাকা" className="bg-slate-50 px-4 py-3 rounded-lg text-sm font-bold" />
                <select value={guestFormData.type} onChange={(e) => setGuestFormData({...guestFormData, type: e.target.value as 'personal' | 'agency'})} className="bg-slate-50 px-4 py-3 rounded-lg text-sm font-bold">
                  <option value="personal">পার্সোনাল</option>
                  <option value="agency">এজেন্সি</option>
                </select>
                <div className="md:col-span-3 flex gap-2">
                  <button type="submit" className="flex-1 btn-gradient text-white py-3 rounded-xl font-black text-xs">সেভ করুন</button>
                  <button type="button" onClick={() => setIsAddingGuest(false)} className="px-6 py-3 bg-slate-100 text-slate-500 rounded-xl font-black text-xs">বাতিল</button>
                </div>
              </form>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {guests.filter(g => !selectedTourForGuests || g.tourId === selectedTourForGuests).map(g => {
              const due = g.totalBill - g.collected;
              return (
                <div key={g.id} className="bg-white p-5 rounded-2xl border border-slate-50 shadow-sm relative overflow-hidden">
                  <div className={`absolute top-0 right-0 px-3 py-1 text-[8px] font-black uppercase tracking-widest ${g.type === 'agency' ? 'bg-indigo-500 text-white' : 'bg-emerald-500 text-white'}`}>
                    {g.type}
                  </div>
                  <h5 className="font-black text-slate-900 mb-1">{g.name}</h5>
                  <p className="text-[10px] text-slate-400 mb-3">{g.phone}</p>
                  <div className="flex justify-between items-end">
                    <div>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">বিল: ৳{g.totalBill}</p>
                      <p className="text-[10px] text-emerald-600 font-black uppercase tracking-widest">পেইড: ৳{g.collected}</p>
                    </div>
                    {due > 0 ? (
                      <div className="text-right">
                        <p className="text-[9px] text-rose-500 font-black uppercase tracking-widest bg-rose-50 px-2 py-1 rounded">বাকি: ৳{due}</p>
                      </div>
                    ) : (
                      <span className="text-emerald-500"><UserCheck size={18} /></span>
                    )}
                  </div>
                  <div className="mt-4 pt-4 border-t border-slate-50 flex gap-2">
                    {g.status === 'pending' && (
                      <button onClick={async () => await updateDoc(doc(db, "guests", g.id), { status: 'received' })} className="flex-1 bg-emerald-50 text-emerald-600 py-2 rounded-lg font-black text-[10px] uppercase">রিসিভ করুন</button>
                    )}
                    <button onClick={async () => await deleteDoc(doc(db, "guests", g.id))} className="px-3 bg-rose-50 text-rose-500 rounded-lg"><Trash2 size={14}/></button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {activeTab === 'analysis' && (
        <div className="space-y-8 animate-in fade-in duration-700">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-50 shadow-sm">
              <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center mb-6 shadow-inner"><DollarSign size={24}/></div>
              <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">মোট কালেকশন (Received)</p>
              <h3 className="text-4xl font-black text-slate-900 tracking-tighter">৳{analysisData.overallCollection}</h3>
            </div>
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-50 shadow-sm">
              <div className="w-12 h-12 bg-rose-50 text-rose-500 rounded-2xl flex items-center justify-center mb-6 shadow-inner"><AlertCircle size={24}/></div>
              <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">মোট বকেয়া (Due Amount)</p>
              <h3 className="text-4xl font-black text-rose-500 tracking-tighter">৳{analysisData.overallDue}</h3>
            </div>
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-50 shadow-sm">
              <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center mb-6 shadow-inner"><TrendingUp size={24}/></div>
              <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">অ্যাক্টিভ ট্যুর</p>
              <h3 className="text-4xl font-black text-slate-900 tracking-tighter">{tours.length}টি</h3>
            </div>
          </div>

          <div className="bg-white rounded-[3rem] p-8 border border-slate-50 shadow-sm overflow-hidden">
            <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-3">
              <Briefcase className="text-indigo-600" /> হোস্ট সেটেলমেন্ট রিপোর্ট
            </h3>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50">
                  <tr>
                    <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">ট্যুরের নাম</th>
                    <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">এজেন্সি কালেকশন</th>
                    <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">পার্সোনাল কালেকশন</th>
                    <th className="px-6 py-4 text-[10px] font-black text-indigo-600 uppercase tracking-widest">মোট কালেকশন</th>
                    <th className="px-6 py-4 text-[10px] font-black text-rose-500 uppercase tracking-widest text-right">বকেয়া</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {analysisData.tourStats.map(s => (
                    <tr key={s.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-5 font-black text-slate-900">{s.name}</td>
                      <td className="px-6 py-5 text-sm font-bold text-slate-600">৳{s.agencyCollection}</td>
                      <td className="px-6 py-5 text-sm font-bold text-slate-600">৳{s.personalCollection}</td>
                      <td className="px-6 py-5 text-sm font-black text-indigo-600">৳{s.totalCollection}</td>
                      <td className="px-6 py-5 text-sm font-black text-rose-500 text-right">৳{s.totalDue}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'users' && (
        <div className="space-y-4">
          <div className="hidden md:block bg-white rounded-3xl overflow-hidden border border-slate-50 shadow-sm">
            <table className="w-full text-left">
              <thead className="bg-slate-50/50">
                <tr>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">মেম্বার</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">স্ট্যাটাস ও রোল</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">অ্যাকশন</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {users.map(u => (
                  <tr key={u.id}>
                    <td className="px-8 py-5">
                      <div className="font-black text-slate-900">{u.name}</div>
                      <div className="text-[11px] text-slate-400">{u.email}</div>
                    </td>
                    <td className="px-8 py-5">
                      <div className="flex flex-col gap-2">
                        <span className={`text-[9px] font-black uppercase tracking-widest ${u.isApproved ? 'text-emerald-500' : 'text-amber-500'}`}>
                          {u.isApproved ? 'Active' : 'Pending'}
                        </span>
                        <select value={u.role} onChange={(e) => onApproveUser(u.id, e.target.value as UserRole)}
                          className="bg-slate-100 px-3 py-1.5 rounded-lg text-[10px] font-black outline-none w-32">
                          <option value={UserRole.GUEST}>গেস্ট</option>
                          <option value={UserRole.MODERATOR}>মডারেটর</option>
                          <option value={UserRole.ADMIN}>এডমিন</option>
                        </select>
                      </div>
                    </td>
                    <td className="px-8 py-5 text-right">
                       <button onClick={() => onDeleteUser(u.id)} className="text-slate-300 hover:text-rose-500 transition-colors">
                        <Trash2 size={18} />
                       </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useMemo } from 'react';
import { Tour, User, UserRole, Guest } from '../types';
import { Plus, Edit, Trash2, Users, LayoutGrid, PieChart, TrendingUp, DollarSign, Briefcase, UserCheck, AlertCircle } from 'lucide-react';
import { doc, setDoc, updateDoc, deleteDoc } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";
import { db } from '../firebase';

interface AdminPanelProps {
  tours: Tour[];
  users: User[];
  guests: Guest[];
  onAddTour: (tour: Omit<Tour, 'id' | 'createdAt'>) => void;
  onUpdateTour: (tour: Tour) => void;
  onDeleteTour: (id: string) => void;
  onApproveUser: (userId: string, role: UserRole) => void;
  onDeleteUser: (userId: string) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ tours, users, guests, onAddTour, onUpdateTour, onDeleteTour, onApproveUser, onDeleteUser }) => {
  const [activeTab, setActiveTab] = useState<'tours' | 'users' | 'guests' | 'analysis'>('tours');
  const [isAddingTour, setIsAddingTour] = useState(false);
  const [editingTour, setEditingTour] = useState<Tour | null>(null);
  const [isAddingGuest, setIsAddingGuest] = useState(false);
  const [selectedTourForGuests, setSelectedTourForGuests] = useState<string>('');

  const [tourFormData, setTourFormData] = useState({
    name: '', driveLink: '', description: '', price: '', bookingNumber: '', imageUrl: ''
  });

  const [guestFormData, setGuestFormData] = useState({
    name: '', phone: '', tourId: '', totalBill: 0, collected: 0, type: 'personal' as 'personal' | 'agency'
  });

  // Host Settlement Logic - Fixed for Caption PTT
  const analysisData = useMemo(() => {
    const tourStats = tours.map(tour => {
      const tourGuests = guests.filter(g => g.tourId === tour.id);

      // Summing all collected amounts (regardless of status for immediate visibility)
      const agencyCollection = tourGuests
        .filter(g => g.type === 'agency')
        .reduce((acc, g) => acc + (g.collected || 0), 0);

      const personalCollection = tourGuests
        .filter(g => g.type === 'personal')
        .reduce((acc, g) => acc + (g.collected || 0), 0);

      const totalCollection = agencyCollection + personalCollection;

      const totalBill = tourGuests.reduce((acc, g) => acc + (g.totalBill || 0), 0);
      const totalDue = totalBill - totalCollection;

      return {
        id: tour.id,
        name: tour.name,
        agencyCollection,
        personalCollection,
        totalCollection,
        totalDue
      };
    });

    const overallCollection = tourStats.reduce((acc, s) => acc + s.totalCollection, 0);
    const overallDue = tourStats.reduce((acc, s) => acc + s.totalDue, 0);

    return { tourStats, overallCollection, overallDue };
  }, [tours, guests]);

  const handleTourSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTour) onUpdateTour({ ...editingTour, ...tourFormData });
    else onAddTour(tourFormData);
    setTourFormData({ name: '', driveLink: '', description: '', price: '', bookingNumber: '', imageUrl: '' });
    setIsAddingTour(false);
    setEditingTour(null);
  };

  const handleGuestSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const id = Math.random().toString(36).substr(2, 9);
    await setDoc(doc(db, "guests", id), {
      ...guestFormData,
      id,
      status: 'pending',
      createdAt: new Date().toISOString()
    });
    setGuestFormData({ name: '', phone: '', tourId: '', totalBill: 0, collected: 0, type: 'personal' });
    setIsAddingGuest(false);
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in slide-in-from-left-4 duration-500 pb-10 px-2 sm:px-0">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl md:text-3xl font-[900] text-slate-900 tracking-tight">ম্যানেজমেন্ট হাব</h2>
          <p className="text-slate-400 text-sm font-medium">Caption PTT এর ট্যুর এবং টিম নিয়ন্ত্রণ করুন</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl w-full sm:w-auto overflow-x-auto no-scrollbar">
          <button onClick={() => setActiveTab('tours')} className={`shrink-0 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'tours' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
            <LayoutGrid size={16} /> ট্যুর
          </button>
          <button onClick={() => setActiveTab('guests')} className={`shrink-0 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'guests' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
            <UserCheck size={16} /> গেস্ট
          </button>
          <button onClick={() => setActiveTab('analysis')} className={`shrink-0 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'analysis' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
            <PieChart size={16} /> অ্যানালাইসিস
          </button>
          <button onClick={() => setActiveTab('users')} className={`shrink-0 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
            <Users size={16} /> টিম
          </button>
        </div>
      </div>

      {activeTab === 'tours' && (
        <div className="space-y-6">
          <div className="flex justify-end">
            {!isAddingTour && (
              <button onClick={() => setIsAddingTour(true)} className="flex items-center gap-2 btn-gradient text-white px-6 py-3.5 rounded-2xl font-black text-xs shadow-lg w-full sm:w-auto justify-center">
                <Plus size={18} /> নতুন ট্যুর যোগ করুন
              </button>
            )}
          </div>
          {isAddingTour && (
             <div className="bg-white rounded-[2rem] p-6 md:p-10 shadow-2xl border border-slate-50">
               <h3 className="text-xl font-black text-slate-900 mb-8">{editingTour ? 'ট্যুর এডিট করুন' : 'নতুন ট্যুর প্যাকেজ'}</h3>
               <form onSubmit={handleTourSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <input required value={tourFormData.name} onChange={(e) => setTourFormData({...tourFormData, name: e.target.value})} placeholder="ট্যুরের নাম" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" />
                 <input required value={tourFormData.driveLink} onChange={(e) => setTourFormData({...tourFormData, driveLink: e.target.value})} placeholder="ড্রাইভ লিঙ্ক" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" />
                 <input required value={tourFormData.price} onChange={(e) => setTourFormData({...tourFormData, price: e.target.value})} placeholder="প্যাকেজ মূল্য (৳)" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" />
                 <input required value={tourFormData.bookingNumber} onChange={(e) => setTourFormData({...tourFormData, bookingNumber: e.target.value})} placeholder="বুকিং নম্বর" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" />
                 <div className="md:col-span-2"><input value={tourFormData.imageUrl} onChange={(e) => setTourFormData({...tourFormData, imageUrl: e.target.value})} placeholder="ছবির ইউআরএল" className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none" /></div>
                 <div className="md:col-span-2"><textarea required rows={4} value={tourFormData.description} onChange={(e) => setTourFormData({...tourFormData, description: e.target.value})} placeholder="বিস্তারিত বর্ণনা..." className="w-full bg-slate-50 px-5 py-4 rounded-xl font-bold text-sm outline-none"></textarea></div>
                 <div className="flex flex-col sm:flex-row gap-3 md:col-span-2">
                   <button type="submit" className="flex-1 btn-gradient text-white py-4 rounded-xl font-black text-xs">সেভ করুন</button>
                   <button type="button" onClick={() => setIsAddingTour(false)} className="px-8 py-4 bg-slate-100 text-slate-500 rounded-xl font-black text-xs">বাতিল</button>
                 </div>
               </form>
             </div>
          )}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {tours.map(t => (
              <div key={t.id} className="bg-white p-6 rounded-2xl border border-slate-50 shadow-sm hover:border-indigo-100 transition-colors">
                <div className="flex items-center justify-between mb-2">
                  <h4 className="font-black text-slate-900">{t.name}</h4>
                  <div className="flex gap-1">
                    <button onClick={() => { setEditingTour(t); setTourFormData(t); setIsAddingTour(true); }} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"><Edit size={16} /></button>
                    <button onClick={() => onDeleteTour(t.id)} className="p-2 text-slate-400 hover:text-rose-600 transition-colors"><Trash2 size={16} /></button>
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">৳{t.price}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'guests' && (
        <div className="space-y-6">
          <div className="flex flex-col sm:flex-row gap-4 justify-between items-start sm:items-center">
            <select value={selectedTourForGuests} onChange={(e) => setSelectedTourForGuests(e.target.value)} className="w-full sm:w-auto bg-white border border-slate-200 px-4 py-3 rounded-xl font-black text-xs outline-none shadow-sm">
              <option value="">সব ট্যুর</option>
              {tours.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
            </select>
            <button onClick={() => setIsAddingGuest(true)} className="w-full sm:w-auto btn-gradient text-white px-6 py-4 rounded-2xl font-black text-xs shadow-lg">
              <Plus size={18} className="inline mr-2" /> গেস্ট যোগ করুন
            </button>
          </div>

          {isAddingGuest && (
            <div className="bg-white rounded-[2rem] p-6 md:p-8 shadow-2xl border border-slate-50 animate-in zoom-in-95 duration-300">
              <h3 className="text-lg font-black text-slate-900 mb-6">গেস্ট ইনফরমেশন এন্ট্রি</h3>
              <form onSubmit={handleGuestSubmit} className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <input required value={guestFormData.name} onChange={(e) => setGuestFormData({...guestFormData, name: e.target.value})} placeholder="নাম" className="bg-slate-50 px-4 py-3.5 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-100" />
                <input required value={guestFormData.phone} onChange={(e) => setGuestFormData({...guestFormData, phone: e.target.value})} placeholder="ফোন" className="bg-slate-50 px-4 py-3.5 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-100" />
                <select required value={guestFormData.tourId} onChange={(e) => setGuestFormData({...guestFormData, tourId: e.target.value})} className="bg-slate-50 px-4 py-3.5 rounded-xl text-sm font-bold outline-none">
                  <option value="">ট্যুর সিলেক্ট করুন</option>
                  {tours.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                </select>
                <input required type="number" value={guestFormData.totalBill} onChange={(e) => setGuestFormData({...guestFormData, totalBill: parseInt(e.target.value) || 0})} placeholder="মোট বিল" className="bg-slate-50 px-4 py-3.5 rounded-xl text-sm font-bold outline-none" />
                <input required type="number" value={guestFormData.collected} onChange={(e) => setGuestFormData({...guestFormData, collected: parseInt(e.target.value) || 0})} placeholder="সংগৃহীত টাকা" className="bg-slate-50 px-4 py-3.5 rounded-xl text-sm font-bold outline-none" />
                <select value={guestFormData.type} onChange={(e) => setGuestFormData({...guestFormData, type: e.target.value as 'personal' | 'agency'})} className="bg-slate-50 px-4 py-3.5 rounded-xl text-sm font-bold outline-none">
                  <option value="personal">পার্সোনাল</option>
                  <option value="agency">এজেন্সি</option>
                </select>
