          <section className="relative text-center space-y-12 py-10 md:py-20 animate-fade-in">
            <div className="inline-flex items-center gap-3 bg-white px-5 py-2.5 rounded-full shadow-lg border border-slate-50 mx-auto">
              <span className="relative flex h-3 w-3">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-3 w-3 bg-indigo-600"></span>
              </span>
              <span className="text-[10px] md:text-[12px] font-black text-slate-800 uppercase tracking-[0.2em]">Premium Travel Experience</span>
            </div>

            <div className="space-y-6">
              <h2 className="text-5xl sm:text-7xl md:text-[10rem] font-[1000] text-slate-900 tracking-tighter leading-[0.85] px-2">
                গন্তব্য হোক <br /> 
                <span className="text-gradient">সীমাহীন</span>
              </h2>
              <p className="text-slate-500 max-w-2xl mx-auto text-lg md:text-2xl font-medium leading-relaxed bengali-text px-6">
                Caption PTT এর সাথে আপনার প্রতিটি যাত্রা হবে আরামদায়ক এবং নিরাপদ। বাংলার প্রতিটি প্রান্তে আমাদের অভিজ্ঞ গাইডরা আছে আপনার অপেক্ষায়।
              </p>
            </div>

            <div className="pt-8 flex justify-center">
               <button 
                onClick={() => window.scrollTo({ top: window.innerHeight * 0.8, behavior: 'smooth' })} 
                className="group flex flex-col items-center gap-4 text-slate-300 hover:text-indigo-600 transition-all duration-500"
              >
                 <span className="text-[10px] font-black uppercase tracking-[0.3em]">নিচে দেখুন</span>
                 <ArrowDownCircle size={48} strokeWidth={1} className="animate-bounce" />
