import { GoogleGenAI } from "@google/genai";

export type CaptionSize = 'small' | 'medium' | 'large';

/**
 * Generates soulful and professional travel captions using the Gemini API.
 */
export async function generateCaptions(
  description: string, 
  price: string, 
  bookingNumber: string, 
  tourName: string,
  size: CaptionSize
): Promise<string> {

  const API_KEY = "AIzaSyAPWGYezWVewQoHzD5mKiMVDZoIbBLL_AA";
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const lengthGuideline = {
    small: "একদম সংক্ষিপ্ত ও আকর্ষণীয় (সর্বোচ্চ ২-৩ লাইন)",
    medium: "মাঝারি এবং তথ্যবহুল (৪-৫ লাইন)",
    large: "বিস্তারিত, কাব্যিক এবং অনেক ইমোজি সহ (৭-১০ লাইন)"
  }[size];

  const prompt = `
    Context: Premium travel agency "Pankhiraj Tour & Travel". 
    Goal: Create a viral, high-converting, and beautiful Bengali social media caption for a tour package.

    Tour Name: ${tourName}
    Price: ${price} BDT
    Contact for Booking: ${bookingNumber}
    Package Details: ${description}
    Length Requirement: ${lengthGuideline}

    Style Guidelines:
    - Use soulful, poetic, and professional Bengali. 
    - Incorporate the brand identity of 'Pankhiraj' (the legendary flying horse) as a metaphor for freedom, magic, and soulful journeys.
    - Use trendy travel emojis (✈️, 🏔️, 🌊, ✨, 🐎).
    - Make the opening hook very strong to grab attention.
    - Highlight the beauty of the destination and the comfort of Pankhiraj services.
    - Use a polite yet persuasive call to action.

    Important: Output ONLY the final caption text. No intro, no explanation.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-flash-latest',
      contents: [{
        parts: [{ text: prompt }]
      }]
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI");

    return text.trim();
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return "দুঃখিত, এই মুহূর্তে ক্যাপশন জেনারেট করা সম্ভব হচ্ছে না। কিছুক্ষণ পর আবার চেষ্টা করুন।";
  }
}

