import React, { useState, useEffect } from 'react';
import { User, Tour, UserRole } from './types';
import Layout from './components/Layout';
import TourCard from './components/TourCard';
import TourDetail from './components/TourDetail';
import AdminPanel from './components/AdminPanel';
import Login from './components/Login';
import { Map, ArrowDownCircle } from 'lucide-react';

// Firebase imports
import { auth, db } from './firebase';
import { onAuthStateChanged, signOut, signInWithEmailAndPassword, createUserWithEmailAndPassword } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { collection, onSnapshot, doc, getDoc, setDoc, updateDoc, deleteDoc, query, orderBy } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

const App: React.FC = () => {
  const [tours, setTours] = useState<Tour[]>(() => {
    const saved = localStorage.getItem('pankhiraj_tours');
    return saved ? JSON.parse(saved) : [];
  });

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('pankhiraj_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(!currentUser);
  const [view, setView] = useState<'home' | 'admin' | 'login' | 'detail'>('home');
  const [selectedTour, setSelectedTour] = useState<Tour | null>(null);

  useEffect(() => {
    localStorage.setItem('pankhiraj_tours', JSON.stringify(tours));
  }, [tours]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('pankhiraj_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('pankhiraj_user');
    }
  }, [currentUser]);

  useEffect(() => {
    let userUnsubscribe: (() => void) | null = null;

    const authUnsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (userUnsubscribe) {
        userUnsubscribe();
        userUnsubscribe = null;
      }

      if (firebaseUser) {
        const userRef = doc(db, "users", firebaseUser.uid);
        userUnsubscribe = onSnapshot(userRef, (userDoc) => {
          if (userDoc.exists()) {
            const userData = userDoc.data() as User;
            if (userData.isApproved) {
              setCurrentUser(userData);
            } else {
              setCurrentUser(null);
            }
          } else {
            setCurrentUser(null);
          }
          setLoading(false);
        }, (error) => {
          console.error("User sync error:", error);
          setLoading(false);
        });
      } else {
        setCurrentUser(null);
        setLoading(false);
      }
    });

    return () => {
      authUnsubscribe();
      if (userUnsubscribe) userUnsubscribe();
    };
  }, []);

  useEffect(() => {
    const q = query(collection(db, "tours"), orderBy("createdAt", "desc"));
    return onSnapshot(q, (snapshot) => {
      const fetchedTours = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Tour));
      setTours(fetchedTours);
    });
  }, []);

  useEffect(() => {
    if (currentUser?.role === UserRole.ADMIN) {
      const usersUnsub = onSnapshot(collection(db, "users"), (snapshot) => {
        setUsers(snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as User)));
      });

      return () => {
        usersUnsub();
      };
    }
  }, [currentUser]);

  const handleLogin = async (email: string, pass: string) => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, pass);
      const userDoc = await getDoc(doc(db, "users", userCredential.user.uid));
      if (userDoc.exists() && (userDoc.data() as User).isApproved) {
        const userData = userDoc.data() as User;
        setCurrentUser(userData);
        setView('home');
        return true;
      }
      return false;
    } catch { return false; }
  };

  const handleRegister = async (name: string, email: string, pass: string) => {
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, pass);
      await setDoc(doc(db, "users", cred.user.uid), {
        id: cred.user.uid, name, email, role: UserRole.GUEST, isApproved: false, createdAt: new Date().toISOString()
      });
      await signOut(auth);
      return true;
    } catch (e: any) {
      return e.code === 'auth/email-already-in-use' ? 'email-in-use' : false;
    }
  };

  const handleLogout = async () => {
    await signOut(auth);
    setCurrentUser(null);
    setView('home');
    setSelectedTour(null);
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#f8fafc]">
        <div className="flex flex-col items-center gap-8 animate-fade-in">
          <div className="relative">
            <div className="w-24 h-24 bg-white rounded-3xl overflow-hidden shadow-2xl flex items-center justify-center animate-pulse border border-slate-100">
              <img src="https://i.postimg.cc/xj3Bb7TR/Untitled_design.png" alt="Logo" className="w-20 h-20 object-cover" />
            </div>
          </div>
          <p className="text-slate-900 font-[900] tracking-[0.3em] uppercase text-xs">Pankhiraj PTT রেডি হচ্ছে</p>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} currentView={view}
      onNavigate={(v) => { setView(v); window.scrollTo({ top: 0, behavior: 'smooth' }); }}>

      {view === 'home' && (
        <div className="space-y-16 md:space-y-32">
          {/* Hero Section */}
          <section className="relative text-center space-y-12 py-10 md:py-20 animate-fade-in">
            <div className="inline-flex items-center gap-3 bg-white px-5 py-2.5 rounded-full shadow-lg border border-slate-50 mx-auto">
              <span className="relative flex h-3 w-3">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-3 w-3 bg-indigo-600"></span>
              </span>
              <span className="text-[10px] md:text-[12px] font-black text-slate-800 uppercase tracking-[0.2em]">Premium Travel Experience</span>
            </div>

            <div className="space-y-6">
              <h2 className="text-5xl sm:text-7xl md:text-[10rem] font-[1000] text-slate-900 tracking-tighter leading-[0.85] px-2">
                গন্তব্য হোক <br /> 
                <span className="text-gradient">সীমাহীন</span>
              </h2>
              <p className="text-slate-500 max-w-2xl mx-auto text-lg md:text-2xl font-medium leading-relaxed bengali-text px-6">
                Pankhiraj PTT এর সাথে আপনার প্রতিটি যাত্রা হবে আরামদায়ক এবং নিরাপদ। বাংলার প্রতিটি প্রান্তে আমাদের অভিজ্ঞ গাইডরা আছে আপনার অপেক্ষায়।
              </p>
            </div>

            <div className="pt-8 flex justify-center">
               <button 
                onClick={() => window.scrollTo({ top: window.innerHeight * 0.8, behavior: 'smooth' })} 
                className="group flex flex-col items-center gap-4 text-slate-300 hover:text-indigo-600 transition-all duration-500"
              >
                 <span className="text-[10px] font-black uppercase tracking-[0.3em]">নিচে দেখুন</span>
                 <ArrowDownCircle size={48} strokeWidth={1} className="animate-bounce" />
               </button>
            </div>
          </section>

          {/* Tours Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8 md:gap-12">
            {tours.map((tour, idx) => (
              <div 
                key={tour.id} 
                className="animate-fade-in" 
                style={{ animationDelay: `${idx * 150}ms` }}
              >
                <TourCard tour={tour} onClick={(t) => { setSelectedTour(t); setView('detail'); window.scrollTo(0,0); }} />
              </div>
            ))}
          </div>

          {tours.length === 0 && (
            <div className="text-center py-40 bg-white rounded-[4rem] border border-slate-100 shadow-xl mx-4 animate-fade-in">
              <div className="w-24 h-24 bg-slate-50 rounded-3xl flex items-center justify-center mx-auto mb-8 shadow-inner">
                <Map size={48} className="text-slate-200" />
              </div>
              <p className="text-slate-900 font-black text-2xl tracking-tight">বর্তমানে কোনো প্যাকেজ নেই</p>
              <p className="text-slate-400 text-sm mt-4 font-medium px-8">খুব শীঘ্রই আমাদের নতুন আকর্ষণীয় সব প্যাকেজ আসছে!</p>
            </div>
          )}
        </div>
      )}

      {view === 'detail' && selectedTour && (
        <TourDetail tour={selectedTour} user={currentUser} onBack={() => setView('home')} />
      )}

      {view === 'login' && (
        <Login onLogin={handleLogin} onRegister={handleRegister} />
      )}

      {view === 'admin' && (currentUser?.role === UserRole.ADMIN || currentUser?.role === UserRole.MODERATOR) && (
        <AdminPanel 
          tours={tours} 
          users={users.filter(u => u.id !== currentUser.id)} 
          onAddTour={async (t) => { const id = Math.random().toString(36).substr(2,9); await setDoc(doc(db,"tours",id),{...t,id,createdAt:new Date().toISOString()}); }}
          onUpdateTour={async (t) => { await updateDoc(doc(db,"tours",t.id),{...t}); }}
          onDeleteTour={async (id) => { if(confirm('আপনি কি এই ট্যুরটি ডিলিট করতে চান?')) await deleteDoc(doc(db,"tours",id)); }}
          onApproveUser={async (id, role) => { await updateDoc(doc(db,"users",id),{isApproved:true,role}); }}
          onDeleteUser={async (id) => { if(confirm('আপনি কি এই মেম্বারকে ডিলিট করতে চান?')) await deleteDoc(doc(db,"users",id)); }}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Tour, User, UserRole } from '../types';
import { Plus, Edit, Trash2, Users, LayoutGrid } from 'lucide-react';

interface AdminPanelProps {
  tours: Tour[];
  users: User[];
  onAddTour: (tour: Omit<Tour, 'id' | 'createdAt'>) => void;
  onUpdateTour: (tour: Tour) => void;
  onDeleteTour: (id: string) => void;
  onApproveUser: (userId: string, role: UserRole) => void;
  onDeleteUser: (userId: string) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ tours, users, onAddTour, onUpdateTour, onDeleteTour, onApproveUser, onDeleteUser }) => {
  const [activeTab, setActiveTab] = useState<'tours' | 'users'>('tours');
  const [isAddingTour, setIsAddingTour] = useState(false);
  const [editingTour, setEditingTour] = useState<Tour | null>(null);

