          <h2 className="text-2xl md:text-3xl font-[900] text-slate-900 tracking-tight">ম্যানেজমেন্ট হাব</h2>
          <p className="text-slate-400 text-sm font-medium">Pankhiraj PTT এর ট্যুর এবং টিম নিয়ন্ত্রণ করুন</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl w-full sm:w-auto overflow-x-auto no-scrollbar">
          <button 
            onClick={() => setActiveTab('tours')} 
            className={`shrink-0 flex items-center justify-center gap-2 px-6 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'tours' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
          >
            <LayoutGrid size={16} /> ট্যুর
          </button>
          <button 
            onClick={() => setActiveTab('users')} 
            className={`shrink-0 flex items-center justify-center gap-2 px-6 py-2.5 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
          >
            <Users size={16} /> টিম
          </button>
        </div>
      </div>

      {activeTab === 'tours' && (
        <div className="space-y-6">
          <div className="flex justify-end">
            {!isAddingTour && (
              <button onClick={() => setIsAddingTour(true)} className="flex items-center gap-2 btn-gradient text-white px-6 py-3.5 rounded-2xl font-black text-xs shadow-lg w-full sm:w-auto justify-center">
                <Plus size={18} /> নতুন ট্যুর যোগ করুন
              </button>
            )}
          </div>
          {isAddingTour && (
             <div className="bg-white rounded-[2rem] p-6 md:p-10 shadow-2xl border border-slate-50">
               <h3 className="text-xl font-black text-slate-900 mb-8">{editingTour ? 'ট্যুর এডিট করুন' : 'নতুন ট্যুর প্যাকেজ'}</h3>
               <form onSubmit={handleTourSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
