export type CaptionSize = 'small' | 'medium' | 'large';

/**
 * Calculates the date for Thursday of the current week in Bengali format.
 * If today is Thursday, returns "আজই".
 */
function getTargetThursdayDate(): string {
  const days = ['রবিবার', 'সোমবার', 'মঙ্গলবার', 'বুধবার', 'বৃহস্পতিবার', 'শুক্রবার', 'শনিবার'];
  const months = ['জানুয়ারি', 'ফেব্রুয়ারি', 'মার্চ', 'এপ্রিল', 'মে', 'জুন', 'জুলাই', 'আগস্ট', 'সেপ্টেম্বর', 'অক্টোবর', 'নভেম্বর', 'ডিসেম্বর'];
  const bengaliDigits: Record<string, string> = {
    '0': '০', '1': '১', '2': '২', '3': '৩', '4': '৪', '5': '৫', '6': '৬', '7': '৭', '8': '৮', '9': '৯'
  };

  const toBengaliNumber = (num: number) => num.toString().split('').map(d => bengaliDigits[d] || d).join('');

  const today = new Date();
  const currentDay = today.getDay(); // 0 (Sun) to 6 (Sat)

  if (currentDay === 4) {
    return "আজই";
  }

  // Calculate days difference to get to Thursday (4)
  // If it's Fri/Sat, it will look ahead to next week's Thurs, 
  // if it's Sun-Wed, it will look at this week's Thurs.
  const diff = 4 - currentDay;
  const targetDate = new Date(today);
  targetDate.setDate(today.getDate() + diff);

  const dateNum = targetDate.getDate();
  const monthName = months[targetDate.getMonth()];

  return `${toBengaliNumber(dateNum)} ই ${monthName} বৃহস্পতিবার`;
}

/**
 * Generates soulful, human-like travel captions using the Gemini API.
 */
export async function generateCaptions(
  description: string, 
  price: string, 
  bookingNumber: string, 
  tourName: string,
  size: CaptionSize
): Promise<string> {

  const API_KEY = "AIzaSyAPWGYezWVewQoHzD5mKiMVDZoIbBLL_AA";
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const thursdayText = getTargetThursdayDate();

  const lengthGuideline = {
    small: "একদম সংক্ষিপ্ত (২-৩ লাইন), সরাসরি মনের কথা।",
    medium: "মাঝারি (৪-৬ লাইন), একটু গল্প আর একটু তথ্য।",
    large: "বিস্তারিত ও কাব্যিক (৮-১০ লাইন), পূর্ণাঙ্গ ভ্রমণ গদ্যের মতো।"
  }[size];

  const prompt = `
    Context: Premium travel agency "Pankhiraj Tour & Travel". 
    Goal: Create a soulful, HUMAN-LIKE, and emotional Bengali social media post. 
    It MUST NOT sound like a generic AI or bot. Write it as if a passionate traveler is sharing a dream.

    Tour Name: ${tourName}
    Price: ${price} BDT
    Contact: ${bookingNumber}
    Package Details: ${description}
    Target Day: ${thursdayText} (Use this date/text naturally in the flow for booking or starting)
    Length: ${lengthGuideline}

    Style Instructions (CRITICAL):
    - Tone: Deeply emotional, warm, and inviting. Use 'চলিত ভাষা' (Colloquial Bengali).
    - Avoid AI clichés like "আপনি কি তৈরি?", "স্বপ্ন পূরণ করুন", "নিশ্চিত করুন". 
    - Use phrases that evoke feelings: "মনটা বড্ড আনচান করছে", "এক চিলতে শান্তি", "স্মৃতি হয়ে থাকবে সারাজীবন".
    - Integrate the brand name 'Pankhiraj' (পঙ্খিরাজ) like a companion, not just a company name.
    - Mention the date "${thursdayText}" as the key day for booking/joining in a friendly way.
    - Structure it naturally with short, punchy sentences and relevant emojis (🏔️, 🌿, ✨, 🐎).
    - Ending should be a soft, polite call to action with the number ${bookingNumber}.

    Output ONLY the caption text. No extra text.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-flash-latest',
      contents: [{
        parts: [{ text: prompt }]
      }]
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI");

    return text.trim();
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return "দুঃখিত, এই মুহূর্তে ক্যাপশন তৈরি করা সম্ভব হচ্ছে না। কিছুক্ষণ পর আবার চেষ্টা করুন।";
  }
}

