import React from 'react';
import { User, UserRole } from '../types';
import { LogOut, ShieldCheck, User as UserIcon, Home, Compass, LayoutDashboard, LogIn } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  user: User | null;
  onLogout: () => void;
  onNavigate: (view: 'home' | 'admin' | 'login') => void;
  currentView: string;
}

const Layout: React.FC<LayoutProps> = ({ children, user, onLogout, onNavigate, currentView }) => {

  // Haptic feedback simulation
  const triggerHaptic = () => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(10);
    }
  };

  const navItem = (view: any, icon: React.ReactNode, label: string) => {
    const isActive = currentView === view;
    return (
      <button 
        onClick={() => { triggerHaptic(); onNavigate(view); }}
        className={`flex flex-col items-center gap-1 flex-1 py-2 transition-all ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}
      >
        <div className={`p-1 rounded-xl transition-all ${isActive ? 'bg-indigo-50 scale-110' : ''}`}>
          {React.cloneElement(icon as React.ReactElement, { size: 22, strokeWidth: isActive ? 2.5 : 2 })}
        </div>
        <span className="text-[10px] font-black uppercase tracking-widest font-['Hind_Siliguri']">{label}</span>
      </button>
    );
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#f8fafc]">
      {/* Top Header */}
      <nav className="fixed top-0 left-0 right-0 z-[100] bg-white/80 backdrop-blur-xl border-b border-slate-100 pt-safe">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          <div 
            className="flex items-center gap-3 cursor-pointer"
            onClick={() => { triggerHaptic(); onNavigate('home'); }}
          >
            <img src="https://i.postimg.cc/xj3Bb7TR/Untitled_design.png" alt="Logo" className="w-9 h-9 rounded-xl shadow-lg" />
            <h1 className="text-xl font-[1000] tracking-tighter text-slate-900">Pankhiraj</h1>
          </div>

          {user && (
            <button 
              onClick={() => { triggerHaptic(); onLogout(); }}
              className="p-2 text-slate-400 hover:text-rose-500 transition-all"
            >
              <LogOut size={20} />
            </button>
          )}
        </div>
      </nav>

      <main className="flex-grow pt-20 pb-32">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          {children}
        </div>
      </main>

      {/* Mobile Bottom Navigation */}
      <div className="fixed bottom-0 left-0 right-0 z-[100] tab-bar-glass pb-safe">
        <div className="flex items-center justify-around max-w-lg mx-auto px-4 h-16">
          {navItem('home', <Home />, 'হোম')}

          {(user?.role === UserRole.ADMIN || user?.role === UserRole.MODERATOR) ? (
            navItem('admin', <LayoutDashboard />, 'প্যানেল')
          ) : (
            <div className="flex-1"></div> // Spacer
          )}

          {user ? (
             <div className="flex flex-col items-center gap-1 flex-1 text-slate-400">
               <div className="w-7 h-7 bg-indigo-600 rounded-full flex items-center justify-center text-white text-[10px] font-bold">
                 {user.name[0]}
               </div>
               <span className="text-[10px] font-black uppercase tracking-widest">প্রোফাইল</span>
             </div>
          ) : (
            navItem('login', <LogIn />, 'লগইন')
          )}
        </div>
      </div>
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { Tour, UserRole, User } from '../types';
import { ExternalLink, Sparkles, Copy, Check, ArrowLeft, Phone, Calendar, Share2, ChevronDown, ChevronUp, Zap, Smartphone, Globe, MessageSquare } from 'lucide-react';
import { generateCaptions, CaptionSize } from '../services/geminiService';

interface TourDetailProps {
  tour: Tour;
  user: User | null;
  onBack: () => void;
}

const TourDetail: React.FC<TourDetailProps> = ({ tour, user, onBack }) => {
  const [caption, setCaption] = useState<string | null>(null);
  const [selectedSize, setSelectedSize] = useState<CaptionSize>('medium');
  const [postType, setPostType] = useState<'page' | 'normal'>('page');
  const [isGenerating, setIsGenerating] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<'main' | 'ai' | null>(null);
  const [isDescExpanded, setIsDescExpanded] = useState(false);

  const triggerHaptic = () => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(10);
    }
  };

  const canAccessTeamTools = user && (user.role === UserRole.ADMIN || user.role === UserRole.MODERATOR);

  const handleGenerate = async () => {
    triggerHaptic();
    if (!canAccessTeamTools) return;
    setIsGenerating(true);
    const bookingNumber = postType === 'page' ? '+8801305497151' : '01314083035';
    try {
      const result = await generateCaptions(tour.description, tour.price, bookingNumber, tour.name, selectedSize);
      setCaption(result);
    } catch (err) { console.error(err); }
