import React, { useState } from 'react';
import { Tour, UserRole, User } from '../types';
import { Sparkles, Copy, Check, ArrowLeft, Phone, Share2, ChevronDown, ChevronUp, Zap, MessageSquare } from 'lucide-react';
import { generateCaptions, CaptionSize } from '../services/geminiService';

interface TourDetailProps {
  tour: Tour;
  user: User | null;
  onBack: () => void;
}

const TourDetail: React.FC<TourDetailProps> = ({ tour, user, onBack }) => {
  const [caption, setCaption] = useState<string | null>(null);
  const [selectedSize, setSelectedSize] = useState<CaptionSize>('medium');
  const [postType, setPostType] = useState<'page' | 'normal'>('page');
  const [isGenerating, setIsGenerating] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<'main' | 'ai' | null>(null);
  const [isDescExpanded, setIsDescExpanded] = useState(false);

  const triggerHaptic = () => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(10);
    }
  };

  const renderTextWithLinks = (text: string) => {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const parts = text.split(urlRegex);
    return parts.map((part, i) => {
      if (part.match(urlRegex)) {
        return (
          <a key={i} href={part} target="_blank" rel="noopener noreferrer" className="clickable-link">
            {part}
          </a>
        );
      }
      return part;
    });
  };

  const canAccessTeamTools = user && (user.role === UserRole.ADMIN || user.role === UserRole.MODERATOR);

  const handleGenerate = async () => {
    triggerHaptic();
    if (!canAccessTeamTools) return;
    setIsGenerating(true);
    const bookingNumber = postType === 'page' ? '+8801305497151' : '01314083035';
    try {
      const result = await generateCaptions(tour.description, tour.price, bookingNumber, tour.name, selectedSize);
      setCaption(result);
    } catch (err) { console.error(err); }
    finally { setIsGenerating(false); }
  };

  const handleCopy = async (text: string, type: 'main' | 'ai') => {
    triggerHaptic();
    try {
      await navigator.clipboard.writeText(text.trim());
      setCopiedIndex(type);
      setTimeout(() => setCopiedIndex(null), 2500);
    } catch (err) { console.error(err); }
  };

  const handleShare = async () => {
    triggerHaptic();
    const shareData = {
      title: tour.name,
      text: `${tour.name} - বুকিং চলছে Pankhiraj PTT তে! মূল্য: ৳${tour.price}`,
      url: window.location.href,
    };
    if (navigator.share) {
      try { await navigator.share(shareData); } catch (err) { console.error(err); }
    } else {
      handleCopy(shareData.text, 'main');
    }
  };

  const openWhatsApp = () => {
    triggerHaptic();
    const text = `আসসালামু আলাইকুম, আমি "${tour.name}" প্যাকেজটি সম্পর্কে জানতে আগ্রহী।`;
    window.open(`https://wa.me/88${tour.bookingNumber.replace(/\D/g,'')}?text=${encodeURIComponent(text)}`, '_blank');
  };

  return (
    <div className="space-y-5 pb-24 animate-in fade-in duration-500">
      {/* Mobile Hero */}
      <div className="relative h-[38vh] -mx-4 -mt-4 overflow-hidden rounded-b-[2rem] shadow-lg">
        <img src={tour.imageUrl} alt={tour.name} className="w-full h-full object-cover" />
        <div className="absolute inset-0 bg-gradient-to-t from-slate-900/90 via-slate-900/20 to-transparent"></div>
        <button 
          onClick={() => { triggerHaptic(); onBack(); }}
          className="absolute top-4 left-4 p-2.5 bg-black/30 backdrop-blur-lg text-white rounded-xl border border-white/20 active:scale-90 transition-all"
        >
          <ArrowLeft size={18} />
        </button>
        <div className="absolute bottom-5 left-5 right-5">
          <span className="bg-indigo-600 text-white px-2.5 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest">{tour.category || 'Pankhiraj'}</span>
          <h2 className="text-2xl font-[1000] text-white mt-2 bengali-text leading-tight drop-shadow-lg">{tour.name}</h2>
        </div>
      </div>

      <div className="flex items-center justify-between p-5 bg-white rounded-2xl border border-slate-50 shadow-sm mx-0.5">
        <div>
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">প্যাকেজ মূল্য</p>
          <p className="text-2xl font-[1000] text-slate-900 tracking-tighter">৳{tour.price}</p>
        </div>
        <button 
          onClick={handleShare}
          className="w-12 h-12 flex items-center justify-center bg-slate-50 text-slate-400 rounded-xl active:scale-90 transition-all"
        >
          <Share2 size={20} />
        </button>
      </div>

      <div className="bg-white rounded-2xl p-5 space-y-3 border border-slate-50 shadow-sm mx-0.5 overflow-hidden">
        <h3 className="text-lg font-black text-slate-900 bengali-text">প্যাকেজ ডিটেইলস</h3>
        <div className={`text-slate-600 bengali-text ${!isDescExpanded ? 'line-clamp-[8]' : ''}`}>
          {renderTextWithLinks(tour.description)}
        </div>
        <button 
          onClick={() => { triggerHaptic(); setIsDescExpanded(!isDescExpanded); }}
          className="text-indigo-600 font-black text-[10px] uppercase tracking-widest flex items-center gap-1.5 pt-2"
        >
          {isDescExpanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
          {isDescExpanded ? 'কম দেখুন' : 'বিস্তারিত পড়ুন'}
        </button>
      </div>

      {/* AI Tools for Team */}
      {canAccessTeamTools && (
        <div className="bg-indigo-50/40 rounded-2xl p-5 border border-indigo-100/50 space-y-5 mx-0.5">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-100">
              <Zap size={18} />
            </div>
            <h3 className="font-black text-slate-900 text-sm bengali-text">এআই ক্যাপশন মেকার</h3>
          </div>

          <div className="flex gap-1.5">
            {(['small', 'medium', 'large'] as CaptionSize[]).map((s) => (
              <button 
                key={s} 
                onClick={() => { triggerHaptic(); setSelectedSize(s); }}
                className={`flex-1 py-2.5 rounded-lg text-[9px] font-black uppercase transition-all ${selectedSize === s ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-slate-400 border border-indigo-50'}`}
              >
                {s === 'small' ? 'ছোট' : s === 'medium' ? 'মাঝারি' : 'বড়'}
              </button>
            ))}
          </div>

          <button 
            onClick={handleGenerate} 
            disabled={isGenerating}
            className="w-full py-3.5 btn-gradient rounded-xl font-black text-xs flex items-center justify-center gap-2 active:scale-[0.98] transition-all"
          >
            {isGenerating ? <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : <><Sparkles size={16} /> জেনারেট ক্যাপশন</>}
          </button>

          {caption && (
            <div className="p-4 bg-white rounded-xl border border-indigo-100 relative group">
              <div className="text-sm text-slate-700 font-bold leading-relaxed bengali-text pr-6">
                {renderTextWithLinks(caption)}
              </div>
              <button 
                onClick={() => handleCopy(caption, 'ai')}
                className="absolute top-2 right-2 p-1.5 text-slate-300 active:text-indigo-600"
              >
                <Copy size={14} />
              </button>
            </div>
          )}
        </div>
      )}

      {/* Sticky Mobile Booking Bar */}
      <div className="fixed bottom-20 left-3 right-3 z-[110] md:relative md:bottom-0 md:left-0 md:right-0">
        <div className="flex gap-2 p-1.5 bg-white/95 backdrop-blur-xl border border-slate-100 rounded-2xl shadow-xl shadow-slate-200/50">
          <button 
            onClick={() => { triggerHaptic(); window.location.href = `tel:${tour.bookingNumber}`; }}
            className="flex-[1] flex items-center justify-center gap-1.5 bg-slate-900 text-white py-3.5 rounded-xl font-black text-[11px] active:scale-95 transition-all"
          >
            <Phone size={16} /> কল
          </button>
          <button 
            onClick={openWhatsApp}
            className="flex-[2] flex items-center justify-center gap-1.5 bg-emerald-500 text-white py-3.5 rounded-xl font-black text-[11px] active:scale-95 transition-all shadow-lg shadow-emerald-100"
          >
            <MessageSquare size={16} /> হোয়াটসঅ্যাপ বুকিং
          </button>
        </div>
      </div>
    </div>
  );
};

export default TourDetail;

import React, { useState } from 'react';
import { Tour, User, UserRole } from '../types';
import { Plus, Edit, Trash2, X } from 'lucide-react';

interface AdminPanelProps {
  tours: Tour[];
  users: User[];
  onAddTour: (tour: Omit<Tour, 'id' | 'createdAt'>) => void;
  onUpdateTour: (tour: Tour) => void;
  onDeleteTour: (id: string) => void;
  onApproveUser: (userId: string, role: UserRole) => void;
  onDeleteUser: (userId: string) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ tours, users, onAddTour, onUpdateTour, onDeleteTour, onApproveUser, onDeleteUser }) => {
  const [activeTab, setActiveTab] = useState<'tours' | 'users'>('tours');
  const [isAddingTour, setIsAddingTour] = useState(false);
  const [editingTour, setEditingTour] = useState<Tour | null>(null);

  const [tourFormData, setTourFormData] = useState({
    name: '', driveLink: '', description: '', price: '', bookingNumber: '', imageUrl: '', category: 'Group Tour'
  });

  const categories = ['Group Tour', 'Couple Package', 'Mountain', 'Sea Beach', 'Historical', 'Day Long'];

  const handleTourSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTour) onUpdateTour({ ...editingTour, ...tourFormData });
    else onAddTour(tourFormData);
    setTourFormData({ name: '', driveLink: '', description: '', price: '', bookingNumber: '', imageUrl: '', category: 'Group Tour' });
    setIsAddingTour(false);
    setEditingTour(null);
  };

  return (
    <div className="space-y-10 pb-20 animate-fade-in px-4 md:px-0">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-[1000] text-slate-900 tracking-tighter">ম্যানেজমেন্ট হাব</h2>
          <p className="text-slate-400 text-sm font-bold uppercase tracking-widest mt-1">Pankhiraj PTT Dashboard</p>
        </div>
        <div className="flex bg-slate-100 p-1.5 rounded-2xl w-full md:w-auto">
          <button onClick={() => setActiveTab('tours')} className={`flex-1 md:px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'tours' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>ট্যুর প্যাকেজ</button>
          <button onClick={() => setActiveTab('users')} className={`flex-1 md:px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>টিম মেম্বারস</button>
        </div>
      </header>

      {activeTab === 'tours' && (
        <div className="space-y-8">
          <div className="flex justify-end">
            {!isAddingTour && (
              <button onClick={() => setIsAddingTour(true)} className="btn-gradient px-8 py-4 rounded-2xl text-xs font-black shadow-xl flex items-center gap-2"><Plus size={18} /> নতুন ট্যুর যোগ করুন</button>
            )}
          </div>

          {isAddingTour && (
            <div className="bg-white p-8 md:p-12 rounded-[2.5rem] border border-slate-100 shadow-2xl animate-in zoom-in-95 duration-500">
               <div className="flex justify-between items-center mb-10">
                 <h3 className="text-2xl font-black text-slate-900 tracking-tight">{editingTour ? 'প্যাকেজ এডিট করুন' : 'নতুন প্যাকেজ তৈরি'}</h3>
                 <button onClick={() => {setIsAddingTour(false); setEditingTour(null);}} className="p-3 text-slate-300 hover:text-slate-900 transition-colors"><X size={24} /></button>
               </div>
               <form onSubmit={handleTourSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
                 <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">ট্যুরের নাম</label>
                   <input required value={tourFormData.name} onChange={(e) => setTourFormData({...tourFormData, name: e.target.value})} className="w-full bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none focus:ring-4 focus:ring-indigo-500/5 transition-all bengali-text" placeholder="যেমন: সাজেক ভ্যালি" />
                 </div>
                 <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">ক্যাটাগরি</label>
                   <select value={tourFormData.category} onChange={(e) => setTourFormData({...tourFormData, category: e.target.value})} className="w-full bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none">
                     {categories.map(c => <option key={c} value={c}>{c}</option>)}
                   </select>
                 </div>
                 <input required value={tourFormData.price} onChange={(e) => setTourFormData({...tourFormData, price: e.target.value})} placeholder="প্যাকেজ মূল্য (৳)" className="bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none" />
                 <input required value={tourFormData.bookingNumber} onChange={(e) => setTourFormData({...tourFormData, bookingNumber: e.target.value})} placeholder="বুকিং নম্বর" className="bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none" />
                 <div className="md:col-span-2"><input value={tourFormData.imageUrl} onChange={(e) => setTourFormData({...tourFormData, imageUrl: e.target.value})} placeholder="ছবির ইউআরএল (যেমন: https://...)" className="w-full bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none" /></div>
                 <div className="md:col-span-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4 mb-2 block">বিস্তারিত বর্ণনা (লাইন ব্রেক কাজ করবে)</label>
                   <textarea required rows={8} value={tourFormData.description} onChange={(e) => setTourFormData({...tourFormData, description: e.target.value})} placeholder="বিস্তারিত বর্ণনা লিখুন। এন্টার চেপে নতুন লাইন শুরু করুন..." className="w-full bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none bengali-text"></textarea>
                 </div>
                 <button type="submit" className="md:col-span-2 btn-gradient py-5 rounded-2xl font-black text-sm shadow-xl active:scale-95 transition-all">সবকিছু সেভ করুন</button>
               </form>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {tours.map(t => (
              <div key={t.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 group shadow-sm">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <span className="text-[9px] font-black text-indigo-500 uppercase tracking-widest">{t.category || 'General'}</span>
                    <h4 className="text-lg font-black text-slate-900 tracking-tight leading-none mt-1 bengali-text">{t.name}</h4>
                  </div>
                  <div className="flex gap-1">
                    <button onClick={() => { setEditingTour(t); setTourFormData(t); setIsAddingTour(true); }} className="p-2 text-slate-300 hover:text-indigo-600 transition-colors"><Edit size={18} /></button>
                    <button onClick={() => onDeleteTour(t.id)} className="p-2 text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                  </div>
                </div>
                <p className="text-lg font-black text-slate-900 tracking-tighter">৳{t.price}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'users' && (
        <div className="bg-white rounded-[2.5rem] overflow-hidden border border-slate-50 shadow-sm overflow-x-auto">
          <table className="w-full text-left min-w-[600px]">
            <thead className="bg-slate-50/50">
              <tr>
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">নাম ও ইমেইল</th>
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">স্ট্যাটাস</th>
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">রোল সিলেক্ট</th>
                <th className="px-10 py-6 text-right"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {users.map(u => (
                <tr key={u.id} className="hover:bg-slate-50/30 transition-all">
                  <td className="px-10 py-6">
                    <p className="font-black text-slate-900">{u.name}</p>
                    <p className="text-[11px] text-slate-400 font-medium">{u.email}</p>
                  </td>
                  <td className="px-10 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${u.isApproved ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                      {u.isApproved ? 'Active' : 'Pending'}
                    </span>
                  </td>
                  <td className="px-10 py-6">
                    <select value={u.role} onChange={(e) => onApproveUser(u.id, e.target.value as UserRole)} className="bg-slate-100 px-4 py-2 rounded-xl text-[10px] font-black outline-none border-none">
                      <option value={UserRole.GUEST}>গেস্ট</option>
                      <option value={UserRole.MODERATOR}>মডারেটর</option>
                      <option value={UserRole.ADMIN}>এডমিন</option>
                    </select>
                  </td>
                  <td className="px-10 py-6 text-right">
                    <button onClick={() => onDeleteUser(u.id)} className="p-3 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 size={20} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

