      if (part.match(urlRegex)) {
        return (
          <a key={i} href={part} target="_blank" rel="noopener noreferrer" className="clickable-link">
            {part}
          </a>
        );
      }
      return part;
    });
  };

  const canAccessTeamTools = user && (user.role === UserRole.ADMIN || user.role === UserRole.MODERATOR);

  const handleGenerate = async () => {
    triggerHaptic();
    if (!canAccessTeamTools) return;
    setIsGenerating(true);
    // Logic: Page uses one number, Normal uses another
    const bookingNumber = postType === 'page' ? '+8801305497151' : '01314083035';
    try {
      const result = await generateCaptions(tour.description, tour.price, bookingNumber, tour.name, selectedSize);
      setCaption(result);
    } catch (err) { 
      console.error(err); 
    } finally { 
      setIsGenerating(false); 
    }
  };

  const handleCopy = async (text: string, type: 'main' | 'ai') => {
    triggerHaptic();
    try {
      await navigator.clipboard.writeText(text.trim());
      setCopiedIndex(type);
      setTimeout(() => setCopiedIndex(null), 2500);
    } catch (err) { console.error(err); }
  };

  const handleShare = async () => {
    triggerHaptic();
    const shareData = {
      title: tour.name,
      text: `${tour.name} - বুকিং চলছে Pankhiraj PTT তে! মূল্য: ৳${tour.price}`,
      url: window.location.href,
    };
    if (navigator.share) {
      try { await navigator.share(shareData); } catch (err) { console.error(err); }
    } else {
      handleCopy(shareData.text, 'main');
    }
  };

  const openWhatsApp = () => {
    triggerHaptic();
    const text = `আসসালামু আলাইকুম, আমি "${tour.name}" প্যাকেজটি সম্পর্কে জানতে আগ্রহী।`;
