        >
          <ArrowLeft size={18} />
        </button>
        <div className="absolute bottom-5 left-5 right-5">
          <span className="bg-indigo-600 text-white px-2.5 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest">{tour.category || 'Pankhiraj'}</span>
          <h2 className="text-2xl font-[1000] text-white mt-2 bengali-text leading-tight drop-shadow-lg">{tour.name}</h2>
        </div>
      </div>

      <div className="flex items-center justify-between p-5 bg-white rounded-2xl border border-slate-50 shadow-sm mx-0.5">
        <div>
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">প্যাকেজ মূল্য</p>
          <p className="text-2xl font-[1000] text-slate-900 tracking-tighter">৳{tour.price}</p>
        </div>
        <button 
