      <div className="bg-white rounded-2xl p-5 space-y-3 border border-slate-50 shadow-sm mx-0.5 overflow-hidden">
        <h3 className="text-lg font-black text-slate-900 bengali-text">প্যাকেজ ডিটেইলস</h3>
        <div className={`text-slate-600 bengali-text ${!isDescExpanded ? 'line-clamp-[8]' : ''}`}>
