import { GoogleGenAI } from "@google/genai";

export type CaptionSize = 'small' | 'medium' | 'large';

/**
 * Calculates the date for Thursday of the current week in Bengali format.
 * If today is Thursday, returns "আজই".
 */
function getTargetThursdayDate(): string {
  const months = ['জানুয়ারি', 'ফেব্রুয়ারি', 'মার্চ', 'এপ্রিল', 'মে', 'জুন', 'জুলাই', 'আগস্ট', 'সেপ্টেম্বর', 'অক্টোবর', 'নভেম্বর', 'ডিসেম্বর'];
  const bengaliDigits: Record<string, string> = {
    '0': '০', '1': '১', '2': '২', '3': '৩', '4': '৪', '5': '৫', '6': '৬', '7': '৭', '8': '৮', '9': '৯'
  };

  const toBengaliNumber = (num: number) => num.toString().split('').map(d => bengaliDigits[d] || d).join('');

  const today = new Date();
  const currentDay = today.getDay(); // 0 (Sun) to 6 (Sat)

  if (currentDay === 4) {
    return "আজই";
  }

  // Calculate days difference to get to Thursday (4)
  const diff = 4 - currentDay;
  const targetDate = new Date(today);
  targetDate.setDate(today.getDate() + diff);

  const dateNum = targetDate.getDate();
  const monthName = months[targetDate.getMonth()];

  return `${toBengaliNumber(dateNum)} ই ${monthName} বৃহস্পতিবার`;
}

/**
 * Generates factual yet soulful human-like travel captions using the Gemini API.
 */
export async function generateCaptions(
  description: string, 
  price: string, 
  bookingNumber: string, 
  tourName: string,
  size: CaptionSize
): Promise<string> {

  const API_KEY = "AIzaSyAPWGYezWVewQoHzD5mKiMVDZoIbBLL_AA";
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const thursdayText = getTargetThursdayDate();

  const lengthGuideline = {
    small: "খুবই ছোট (১-২ লাইন)। সরাসরি ট্যুরের মূল আকর্ষণ আর দাম থাকবে।",
    medium: "মাঝারি (৩-৪ লাইন)। ট্যুরের ১-২টি বিশেষত্ব আর বুকিং তথ্য থাকবে।",
    large: "৫-৭ লাইন। ট্যুরের ইনফরমেশনগুলো একটু গুছিয়ে কাব্যিক ঢঙে বলা হবে।"
  }[size];

  const prompt = `
    Context: Premium travel agency "Pankhirajtravel". 
    Goal: Create a factual yet emotional Bengali social media post for "${tourName}".

    Tour Information to Include:
    - Tour Name: ${tourName}
    - Highlights/Details: ${description} (Pick the most important points from here)
    - Price: ${price} BDT
    - Booking/Start Day: ${thursdayText}
    - Helpline: ${bookingNumber}

    Constraint: ${lengthGuideline} (Keep it concise, don't write too much).

    Writing Style:
    - MUST sound like a real person writing a post, not AI. 
    - Use colloquial Bengali (চলিত ভাষা).
    - Avoid over-used words like "নিশ্চিত করুন", "অপেক্ষা করছে", "স্বপ্নপূরণ".
    - Focus on the experience described in the 'Highlights'. If the description says "Hotel included", mention it naturally.
    - Integration: Mention that booking is open till ${thursdayText} (or starts then).
    - Use few but effective emojis (✈️, 🏔️, ✨).

    Output ONLY the caption text.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-flash-latest',
      contents: [{
        parts: [{ text: prompt }]
      }]
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI");

    return text.trim();
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return "দুঃখিত, এই মুহূর্তে ক্যাপশন তৈরি করা সম্ভব হচ্ছে না।";
  }
}

import React, { useState } from 'react';
import { Tour, UserRole, User } from '../types';
import { Sparkles, Copy, Check, ArrowLeft, Phone, Share2, ChevronDown, ChevronUp, Zap, MessageSquare, Layout, User as UserIcon } from 'lucide-react';
import { generateCaptions, CaptionSize } from '../services/geminiService';

interface TourDetailProps {
  tour: Tour;
  user: User | null;
  onBack: () => void;
}

const TourDetail: React.FC<TourDetailProps> = ({ tour, user, onBack }) => {
  const [caption, setCaption] = useState<string | null>(null);
  const [selectedSize, setSelectedSize] = useState<CaptionSize>('medium');
  const [postType, setPostType] = useState<'page' | 'normal'>('page');
  const [isGenerating, setIsGenerating] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<'main' | 'ai' | null>(null);
  const [isDescExpanded, setIsDescExpanded] = useState(false);

  const triggerHaptic = () => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(10);
    }
  };

  const renderTextWithLinks = (text: string) => {
    if (!text) return null;
    // Regex for URLs starting with http:// or https://
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const parts = text.split(urlRegex);

    return parts.map((part, i) => {
      if (part.match(urlRegex)) {
        return (
          <a 
            key={i} 
            href={part} 
            target="_blank" 
            rel="noopener noreferrer" 
            className="clickable-link"
            onClick={(e) => e.stopPropagation()}
          >
            {part}
          </a>
        );
      }
      return part;
    });
  };

  const canAccessTeamTools = user && (user.role === UserRole.ADMIN || user.role === UserRole.MODERATOR);

  const handleGenerate = async () => {
    triggerHaptic();
    if (!canAccessTeamTools) return;
    setIsGenerating(true);
    // Logic: Page uses one number, Normal uses another
    const bookingNumber = postType === 'page' ? '+8801305497151' : '01314083035';
    try {
      const result = await generateCaptions(tour.description, tour.price, bookingNumber, tour.name, selectedSize);
      setCaption(result);
    } catch (err) { 
      console.error(err); 
    } finally { 
      setIsGenerating(false); 
    }
  };

  const handleCopy = async (text: string, type: 'main' | 'ai') => {
    triggerHaptic();
    try {
      await navigator.clipboard.writeText(text.trim());
      setCopiedIndex(type);
      setTimeout(() => setCopiedIndex(null), 2500);
    } catch (err) { console.error(err); }
  };

  const handleShare = async () => {
    triggerHaptic();
    const shareData = {
      title: tour.name,
      text: `${tour.name} - বুকিং চলছে Pankhirajtravel-এ! মূল্য: ৳${tour.price}`,
      url: window.location.href,
    };
    if (navigator.share) {
      try { await navigator.share(shareData); } catch (err) { console.error(err); }
    } else {
      handleCopy(shareData.text, 'main');
    }
  };

  const openWhatsApp = () => {
    triggerHaptic();
    const text = `আসসালামু আলাইকুম, আমি "${tour.name}" প্যাকেজটি সম্পর্কে জানতে আগ্রহী।`;
    window.open(`https://wa.me/88${tour.bookingNumber.replace(/\D/g,'')}?text=${encodeURIComponent(text)}`, '_blank');
  };

  return (
    <div className="space-y-5 pb-24 animate-in fade-in duration-500">
      {/* Mobile Hero */}
      <div className="relative h-[38vh] -mx-4 -mt-4 overflow-hidden rounded-b-[2rem] shadow-lg">
        <img src={tour.imageUrl} alt={tour.name} className="w-full h-full object-cover" />
        <div className="absolute inset-0 bg-gradient-to-t from-slate-900/90 via-slate-900/20 to-transparent"></div>
        <button 
          onClick={() => { triggerHaptic(); onBack(); }}
          className="absolute top-4 left-4 p-2.5 bg-black/30 backdrop-blur-lg text-white rounded-xl border border-white/20 active:scale-90 transition-all"
        >
          <ArrowLeft size={18} />
        </button>
        <div className="absolute bottom-5 left-5 right-5">
          <span className="bg-indigo-600 text-white px-2.5 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest">{tour.category || 'Pankhirajtravel'}</span>
          <h2 className="text-2xl font-[1000] text-white mt-2 bengali-text leading-tight drop-shadow-lg">{tour.name}</h2>
        </div>
      </div>

      <div className="flex items-center justify-between p-5 bg-white rounded-2xl border border-slate-50 shadow-sm mx-0.5">
        <div>
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">প্যাকেজ মূল্য</p>
          <p className="text-2xl font-[1000] text-slate-900 tracking-tighter">৳{tour.price}</p>
        </div>
        <button 
          onClick={handleShare}
          className="w-12 h-12 flex items-center justify-center bg-slate-50 text-slate-400 rounded-xl active:scale-90 transition-all"
        >
          <Share2 size={20} />
        </button>
      </div>

      <div className="bg-white rounded-2xl p-5 space-y-3 border border-slate-50 shadow-sm mx-0.5 overflow-hidden">
        <h3 className="text-lg font-black text-slate-900 bengali-text">প্যাকেজ ডিটেইলস</h3>
        <div className={`text-slate-600 bengali-text ${!isDescExpanded ? 'line-clamp-[10]' : ''}`}>
          {renderTextWithLinks(tour.description)}
        </div>
        <button 
          onClick={() => { triggerHaptic(); setIsDescExpanded(!isDescExpanded); }}
          className="text-indigo-600 font-black text-[10px] uppercase tracking-widest flex items-center gap-1.5 pt-2"
        >
          {isDescExpanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
          {isDescExpanded ? 'কম দেখুন' : 'বিস্তারিত পড়ুন'}
        </button>
      </div>

      {/* AI Tools for Team */}
      {canAccessTeamTools && (
        <div className="bg-indigo-50/40 rounded-2xl p-5 border border-indigo-100/50 space-y-5 mx-0.5">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-9 h-9 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-100">
                <Zap size={18} />
              </div>
              <h3 className="font-black text-slate-900 text-sm bengali-text">এআই ক্যাপশন মেকার</h3>
            </div>
          </div>

          {/* Post Type Selector */}
          <div className="space-y-2">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">পোস্টের ধরন</p>
            <div className="flex gap-1.5 p-1 bg-white rounded-xl border border-indigo-50">
              <button 
                onClick={() => { triggerHaptic(); setPostType('page'); }}
                className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${postType === 'page' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400'}`}
              >
                <Layout size={14} /> পেজ পোস্ট
              </button>
              <button 
                onClick={() => { triggerHaptic(); setPostType('normal'); }}
                className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg text-[10px] font-black uppercase transition-all ${postType === 'normal' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400'}`}
              >
                <UserIcon size={14} /> পার্সোনাল
              </button>
            </div>
          </div>

          <div className="space-y-2">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">ক্যাপশন সাইজ</p>
            <div className="flex gap-1.5">
              {(['small', 'medium', 'large'] as CaptionSize[]).map((s) => (
                <button 
                  key={s} 
                  onClick={() => { triggerHaptic(); setSelectedSize(s); }}
                  className={`flex-1 py-2.5 rounded-lg text-[9px] font-black uppercase transition-all ${selectedSize === s ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-slate-400 border border-indigo-50'}`}
                >
                  {s === 'small' ? 'ছোট' : s === 'medium' ? 'মাঝারি' : 'বড়'}
                </button>
              ))}
            </div>
          </div>

          <button 
            onClick={handleGenerate} 
            disabled={isGenerating}
            className="w-full py-3.5 btn-gradient rounded-xl font-black text-xs flex items-center justify-center gap-2 active:scale-[0.98] transition-all"
          >
            {isGenerating ? <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : <><Sparkles size={16} /> জেনারেট ক্যাপশন</>}
          </button>

          {caption && (
            <div className="p-4 bg-white rounded-xl border border-indigo-100 relative group animate-in slide-in-from-bottom-2 duration-300">
              <div className="text-sm text-slate-700 font-bold leading-relaxed bengali-text pr-8">
                {renderTextWithLinks(caption)}
              </div>
              <button 
                onClick={() => handleCopy(caption, 'ai')}
                className="absolute top-3 right-3 p-1.5 text-slate-300 hover:text-indigo-600 active:scale-90 transition-all"
              >
                {copiedIndex === 'ai' ? <Check size={16} className="text-emerald-500" /> : <Copy size={16} />}
              </button>
            </div>
          )}
        </div>
      )}

      {/* Sticky Mobile Booking Bar */}
      <div className="fixed bottom-20 left-3 right-3 z-[110] md:relative md:bottom-0 md:left-0 md:right-0">
        <div className="flex gap-2 p-1.5 bg-white/95 backdrop-blur-xl border border-slate-100 rounded-2xl shadow-xl shadow-slate-200/50">
          <button 
            onClick={() => { triggerHaptic(); window.location.href = `tel:${tour.bookingNumber}`; }}
            className="flex-[1] flex items-center justify-center gap-1.5 bg-slate-900 text-white py-3.5 rounded-xl font-black text-[11px] active:scale-95 transition-all"
          >
            <Phone size={16} /> কল
          </button>
          <button 
            onClick={openWhatsApp}
            className="flex-[2] flex items-center justify-center gap-1.5 bg-emerald-500 text-white py-3.5 rounded-xl font-black text-[11px] active:scale-95 transition-all shadow-lg shadow-emerald-100"
          >
            <MessageSquare size={16} /> হোয়াটসঅ্যাপ বুকিং
          </button>
        </div>
      </div>
    </div>
  );
};

