            <h1 className="text-xl font-[1000] tracking-tighter text-slate-900 uppercase">PTT</h1>
          </div>

          {user && (
            <button 
              onClick={() => { triggerHaptic(); onLogout(); }}
              className="p-2 text-slate-400 hover:text-rose-500 transition-all"
            >
              <LogOut size={20} />
