import React, { useState, useEffect, useMemo } from 'react';
import { User, Tour, UserRole } from './types';
import Layout from './components/Layout';
import TourCard from './components/TourCard';
import TourDetail from './components/TourDetail';
import AdminPanel from './components/AdminPanel';
import Login from './components/Login';
import { Map, ArrowDownCircle, Search, SlidersHorizontal } from 'lucide-react';

// Firebase imports
import { auth, db } from './firebase';
import { onAuthStateChanged, signOut, signInWithEmailAndPassword, createUserWithEmailAndPassword } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { collection, onSnapshot, doc, getDoc, setDoc, updateDoc, deleteDoc, query, orderBy } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

const App: React.FC = () => {
  const [tours, setTours] = useState<Tour[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState<'home' | 'admin' | 'login' | 'detail'>('home');
  const [selectedTour, setSelectedTour] = useState<Tour | null>(null);

  // Search and Filter States
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');

  const categories = useMemo(() => {
    const cats = new Set(tours.map(t => t.category).filter(Boolean));
    return ['All', ...Array.from(cats)];
  }, [tours]);

  const filteredTours = useMemo(() => {
    return tours.filter(tour => {
      const matchesSearch = tour.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           tour.description.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'All' || tour.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [tours, searchQuery, selectedCategory]);

  useEffect(() => {
    const authUnsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        const userRef = doc(db, "users", firebaseUser.uid);
        onSnapshot(userRef, (userDoc) => {
          if (userDoc.exists() && userDoc.data().isApproved) {
            setCurrentUser(userDoc.data() as User);
          } else {
            setCurrentUser(null);
          }
          setLoading(false);
        });
      } else {
        setCurrentUser(null);
        setLoading(false);
      }
    });
    return () => authUnsubscribe();
  }, []);

  useEffect(() => {
    const q = query(collection(db, "tours"), orderBy("createdAt", "desc"));
    return onSnapshot(q, (snapshot) => {
      const fetchedTours = snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as Tour));
      setTours(fetchedTours);
    });
  }, []);

  useEffect(() => {
    if (currentUser?.role === UserRole.ADMIN) {
      return onSnapshot(collection(db, "users"), (snapshot) => {
        setUsers(snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as User)));
      });
    }
  }, [currentUser]);

  const handleLogin = async (email: string, pass: string) => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, pass);
      const userDoc = await getDoc(doc(db, "users", userCredential.user.uid));
      return userDoc.exists() && (userDoc.data() as User).isApproved;
    } catch { return false; }
  };

  const handleRegister = async (name: string, email: string, pass: string) => {
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, pass);
      await setDoc(doc(db, "users", cred.user.uid), {
        id: cred.user.uid, name, email, role: UserRole.GUEST, isApproved: false, createdAt: new Date().toISOString()
      });
      await signOut(auth);
      return true;
    } catch (e: any) { return e.code === 'auth/email-already-in-use' ? 'email-in-use' : false; }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#f8fafc]">
        <div className="flex flex-col items-center gap-6 animate-pulse">
           <img src="https://i.postimg.cc/xj3Bb7TR/Untitled_design.png" alt="Logo" className="w-20 h-20 object-cover rounded-3xl" />
           <p className="text-slate-400 font-black tracking-[0.3em] uppercase text-[10px]">PTT Loading...</p>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={() => signOut(auth)} currentView={view} onNavigate={setView}>
      {view === 'home' && (
        <div className="space-y-8 md:space-y-12">
          {/* Hero */}
          <section className="text-center space-y-6 md:space-y-8 pt-6 md:pt-10">
            <h2 className="text-4xl md:text-8xl font-[1000] text-slate-900 tracking-tighter leading-tight md:leading-none text-balance bengali-text">
              গন্তব্য হোক <span className="text-gradient">সীমাহীন</span>
            </h2>

            {/* Search Bar */}
            <div className="max-w-xl mx-auto relative group px-4">
              <div className="absolute inset-0 bg-indigo-500/5 blur-2xl group-focus-within:bg-indigo-500/15 transition-all rounded-full"></div>
              <div className="relative flex items-center bg-white border border-slate-100 rounded-2xl md:rounded-3xl p-1.5 md:p-2 shadow-lg shadow-indigo-100/30">
                <div className="pl-4 pr-2 text-slate-400">
                  <Search size={18} />
                </div>
                <input 
                  type="text" 
                  placeholder="আপনার গন্তব্য খুঁজুন..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full bg-transparent py-2.5 md:py-3 outline-none font-bold text-slate-700 bengali-text text-sm md:text-base"
                />
              </div>
            </div>

            {/* Categories */}
            <div className="flex flex-wrap justify-center gap-2 px-2 overflow-x-auto pb-2 no-scrollbar">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat || 'All')}
                  className={`whitespace-nowrap px-5 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-wider transition-all active:scale-95 ${selectedCategory === cat ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-50'}`}
                >
                  {cat === 'All' ? 'সবগুলো' : cat}
                </button>
              ))}
            </div>
          </section>

          {/* Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-10">
            {filteredTours.map((tour) => (
              <TourCard key={tour.id} tour={tour} onClick={(t) => { setSelectedTour(t); setView('detail'); }} />
            ))}
          </div>

          {filteredTours.length === 0 && (
            <div className="text-center py-24 bg-white rounded-3xl border border-slate-50 mx-4">
              <p className="text-slate-400 font-bold bengali-text">দুঃখিত, কোনো প্যাকেজ খুঁজে পাওয়া যায়নি।</p>
            </div>
          )}
        </div>
      )}

      {view === 'detail' && selectedTour && (
        <TourDetail tour={selectedTour} user={currentUser} onBack={() => setView('home')} />
      )}

      {view === 'login' && <Login onLogin={handleLogin} onRegister={handleRegister} />}

      {view === 'admin' && currentUser && (
        <AdminPanel 
          tours={tours} users={users} 
          onAddTour={async (t) => { const id = Math.random().toString(36).substr(2,9); await setDoc(doc(db,"tours",id),{...t,id,createdAt:new Date().toISOString()}); }}
          onUpdateTour={async (t) => { await updateDoc(doc(db,"tours",t.id),{...t}); }}
          onDeleteTour={async (id) => { if(confirm('ডিলিট করতে চান?')) await deleteDoc(doc(db,"tours",id)); }}
          onApproveUser={async (id, role) => { await updateDoc(doc(db,"users",id),{isApproved:true,role}); }}
          onDeleteUser={async (id) => { if(confirm('ডিলিট করতে চান?')) await deleteDoc(doc(db,"users",id)); }}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
