interface TourDetailProps {
  tour: Tour;
  user: User | null;
  onBack: () => void;
}

const TourDetail: React.FC<TourDetailProps> = ({ tour, user, onBack }) => {
  const [caption, setCaption] = useState<string | null>(null);
  const [selectedSize, setSelectedSize] = useState<CaptionSize>('medium');
  const [postType, setPostType] = useState<'page' | 'normal'>('page');
  const [isGenerating, setIsGenerating] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<'main' | 'ai' | null>(null);
  const [isDescExpanded, setIsDescExpanded] = useState(false);

  // Specified central booking number
  const AGENCY_BOOKING_NUMBER = '+8801305497151';

  const triggerHaptic = () => {
    if (window.navigator && window.navigator.vibrate) {
      window.navigator.vibrate(10);
    }
  };

  const renderTextWithLinks = (text: string) => {
    if (!text) return null;
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const parts = text.split(urlRegex);

    return parts.map((part, i) => {
      if (part.match(urlRegex)) {
        return (
