              <div className="text-sm text-slate-700 font-bold leading-relaxed bengali-text pr-8">
                {renderTextWithLinks(caption)}
              </div>
              <button 
                onClick={() => handleCopy(caption, 'ai')}
                className="absolute top-3 right-3 p-1.5 text-slate-300 hover:text-indigo-600 active:scale-90 transition-all"
              >
                {copiedIndex === 'ai' ? <Check size={16} className="text-emerald-500" /> : <Copy size={16} />}
              </button>
            </div>
          )}
        </div>
      )}

      {/* Sticky Mobile Booking Bar */}
      <div className="fixed bottom-20 left-3 right-3 z-[110] md:relative md:bottom-0 md:left-0 md:right-0">
        <div className="flex gap-2 p-1.5 bg-white/95 backdrop-blur-xl border border-slate-100 rounded-2xl shadow-xl shadow-slate-200/50">
          <button 
            onClick={() => { triggerHaptic(); window.location.href = `tel:${AGENCY_BOOKING_NUMBER}`; }}
            className="flex-[1] flex items-center justify-center gap-1.5 bg-slate-900 text-white py-3.5 rounded-xl font-black text-[11px] active:scale-95 transition-all"
          >
            <Phone size={16} /> কল
          </button>
          <button 
            onClick={openWhatsApp}
            className="flex-[2] flex items-center justify-center gap-1.5 bg-emerald-500 text-white py-3.5 rounded-xl font-black text-[11px] active:scale-95 transition-all shadow-lg shadow-emerald-100"
          >
            <MessageSquare size={16} /> হোয়াটসঅ্যাপ বুকিং
          </button>
        </div>
      </div>
    </div>
  );
};

export default TourDetail;

export enum UserRole {
  GUEST = 'guest',
  MODERATOR = 'moderator',
  ADMIN = 'admin'
}

export interface User {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  isApproved: boolean;
  createdAt: string;
}

export interface Tour {
  id: string;
  name: string;
  driveLink: string;
  description: string;
  price: string;
  bookingNumber: string;
  imageUrl: string;
  createdAt: string;
  categories: string[]; // Changed from single category to array
}

export interface Guest {
  id: string;
  tourId: string;
  name: string;
  phone: string;
  totalBill: number;
  collected: number;
  type: 'agency' | 'personal';
  status: 'pending' | 'received';
  createdAt: string;
}

export interface AppState {
  currentUser: User | null;
  tours: Tour[];
  users: User[];
  guests: Guest[];
  isAuthLoading: boolean;
}

import React, { useState, useEffect, useMemo } from 'react';
import { User, Tour, UserRole } from './types';
import Layout from './components/Layout';
import TourCard from './components/TourCard';
import TourDetail from './components/TourDetail';
import AdminPanel from './components/AdminPanel';
import Login from './components/Login';
import { Map, ArrowDownCircle, Search, SlidersHorizontal } from 'lucide-react';

// Firebase imports
import { auth, db } from './firebase';
import { onAuthStateChanged, signOut, signInWithEmailAndPassword, createUserWithEmailAndPassword } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { collection, onSnapshot, doc, getDoc, setDoc, updateDoc, deleteDoc, query, orderBy } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

const App: React.FC = () => {
  const [tours, setTours] = useState<Tour[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState<'home' | 'admin' | 'login' | 'detail'>('home');
  const [selectedTour, setSelectedTour] = useState<Tour | null>(null);

  // Search and Filter States
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('All');

  const categories = useMemo(() => {
    const cats = new Set<string>();
    tours.forEach(t => {
      if (t.categories && Array.isArray(t.categories)) {
        t.categories.forEach(c => cats.add(c));
      }
    });
    return ['All', ...Array.from(cats)];
  }, [tours]);

  const filteredTours = useMemo(() => {
    return tours.filter(tour => {
      const matchesSearch = tour.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           tour.description.toLowerCase().includes(searchQuery.toLowerCase());

      const tourCats = tour.categories || [];
      const matchesCategory = selectedCategory === 'All' || tourCats.includes(selectedCategory);

      return matchesSearch && matchesCategory;
    });
  }, [tours, searchQuery, selectedCategory]);

  useEffect(() => {
    const authUnsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        const userRef = doc(db, "users", firebaseUser.uid);
        onSnapshot(userRef, (userDoc) => {
          if (userDoc.exists() && userDoc.data().isApproved) {
            setCurrentUser(userDoc.data() as User);
          } else {
            setCurrentUser(null);
          }
          setLoading(false);
        });
      } else {
        setCurrentUser(null);
        setLoading(false);
      }
    });
    return () => authUnsubscribe();
  }, []);

  useEffect(() => {
    const q = query(collection(db, "tours"), orderBy("createdAt", "desc"));
    return onSnapshot(q, (snapshot) => {
      const fetchedTours = snapshot.docs.map(doc => {
        const data = doc.data();
        return { 
          ...data, 
          id: doc.id,
          categories: Array.isArray(data.categories) ? data.categories : (data.category ? [data.category] : [])
        } as Tour;
      });
      setTours(fetchedTours);
    });
  }, []);

  useEffect(() => {
    if (currentUser?.role === UserRole.ADMIN) {
      return onSnapshot(collection(db, "users"), (snapshot) => {
        setUsers(snapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as User)));
      });
    }
  }, [currentUser]);

  const handleLogin = async (email: string, pass: string) => {
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, pass);
      const userDoc = await getDoc(doc(db, "users", userCredential.user.uid));
      return userDoc.exists() && (userDoc.data() as User).isApproved;
    } catch { return false; }
  };

  const handleRegister = async (name: string, email: string, pass: string) => {
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, pass);
      await setDoc(doc(db, "users", cred.user.uid), {
        id: cred.user.uid, name, email, role: UserRole.GUEST, isApproved: false, createdAt: new Date().toISOString()
      });
      await signOut(auth);
      return true;
    } catch (e: any) { return e.code === 'auth/email-already-in-use' ? 'email-in-use' : false; }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#f8fafc]">
        <div className="flex flex-col items-center gap-6 animate-pulse">
           <img src="https://i.postimg.cc/xj3Bb7TR/Untitled_design.png" alt="Logo" className="w-20 h-20 object-cover rounded-3xl" />
           <p className="text-slate-400 font-black tracking-[0.3em] uppercase text-[10px]">PTT Loading...</p>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={() => signOut(auth)} currentView={view} onNavigate={setView}>
      {view === 'home' && (
        <div className="space-y-8 md:space-y-12">
          {/* Hero */}
          <section className="text-center space-y-6 md:space-y-8 pt-6 md:pt-10">
            <h2 className="text-4xl md:text-8xl font-[1000] text-slate-900 tracking-tighter leading-tight md:leading-none text-balance bengali-text">
              গন্তব্য হোক <span className="text-gradient">সীমাহীন</span>
            </h2>

            {/* Search Bar */}
            <div className="max-w-xl mx-auto relative group px-4">
              <div className="absolute inset-0 bg-indigo-500/5 blur-2xl group-focus-within:bg-indigo-500/15 transition-all rounded-full"></div>
              <div className="relative flex items-center bg-white border border-slate-100 rounded-2xl md:rounded-3xl p-1.5 md:p-2 shadow-lg shadow-indigo-100/30">
                <div className="pl-4 pr-2 text-slate-400">
                  <Search size={18} />
                </div>
                <input 
                  type="text" 
                  placeholder="আপনার গন্তব্য খুঁজুন..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full bg-transparent py-2.5 md:py-3 outline-none font-bold text-slate-700 bengali-text text-sm md:text-base"
                />
              </div>
            </div>

            {/* Categories */}
            <div className="flex flex-wrap justify-center gap-2 px-2 overflow-x-auto pb-2 no-scrollbar">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  className={`whitespace-nowrap px-5 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-wider transition-all active:scale-95 ${selectedCategory === cat ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-slate-400 border border-slate-50'}`}
                >
                  {cat === 'All' ? 'সবগুলো' : cat}
                </button>
              ))}
            </div>
          </section>

          {/* Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-10">
            {filteredTours.map((tour) => (
              <TourCard key={tour.id} tour={tour} onClick={(t) => { setSelectedTour(t); setView('detail'); }} />
            ))}
          </div>

          {filteredTours.length === 0 && (
            <div className="text-center py-24 bg-white rounded-3xl border border-slate-50 mx-4">
              <p className="text-slate-400 font-bold bengali-text">দুঃখিত, কোনো প্যাকেজ খুঁজে পাওয়া যায়নি।</p>
            </div>
          )}
        </div>
      )}

      {view === 'detail' && selectedTour && (
        <TourDetail tour={selectedTour} user={currentUser} onBack={() => setView('home')} />
      )}

      {view === 'login' && <Login onLogin={handleLogin} onRegister={handleRegister} />}

      {view === 'admin' && currentUser && (
        <AdminPanel 
          tours={tours} users={users} 
          onAddTour={async (t) => { const id = Math.random().toString(36).substr(2,9); await setDoc(doc(db,"tours",id),{...t,id,createdAt:new Date().toISOString()}); }}
          onUpdateTour={async (t) => { await updateDoc(doc(db,"tours",t.id),{...t}); }}
          onDeleteTour={async (id) => { if(confirm('ডিলিট করতে চান?')) await deleteDoc(doc(db,"tours",id)); }}
          onApproveUser={async (id, role) => { await updateDoc(doc(db,"users",id),{isApproved:true,role}); }}
          onDeleteUser={async (id) => { if(confirm('ডিলিট করতে চান?')) await deleteDoc(doc(db,"users",id)); }}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Tour, User, UserRole } from '../types';
import { Plus, Edit, Trash2, X, Check } from 'lucide-react';

interface AdminPanelProps {
  tours: Tour[];
  users: User[];
  onAddTour: (tour: Omit<Tour, 'id' | 'createdAt'>) => void;
  onUpdateTour: (tour: Tour) => void;
  onDeleteTour: (id: string) => void;
  onApproveUser: (userId: string, role: UserRole) => void;
  onDeleteUser: (userId: string) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ tours, users, onAddTour, onUpdateTour, onDeleteTour, onApproveUser, onDeleteUser }) => {
  const [activeTab, setActiveTab] = useState<'tours' | 'users'>('tours');
  const [isAddingTour, setIsAddingTour] = useState(false);
  const [editingTour, setEditingTour] = useState<Tour | null>(null);

  const [tourFormData, setTourFormData] = useState<{
    name: string; driveLink: string; description: string; price: string; bookingNumber: string; imageUrl: string; categories: string[];
  }>({
    name: '', driveLink: '', description: '', price: '', bookingNumber: '', imageUrl: '', categories: []
  });

  const availableCategories = ['Group Tour', 'Couple Package', 'Mountain', 'Sea Beach', 'Historical', 'Day Long', 'Relax'];

  const toggleCategory = (cat: string) => {
    setTourFormData(prev => {
      const exists = prev.categories.includes(cat);
      if (exists) {
        return { ...prev, categories: prev.categories.filter(c => c !== cat) };
      } else {
        return { ...prev, categories: [...prev.categories, cat] };
      }
    });
  };

  const handleTourSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTour) onUpdateTour({ ...editingTour, ...tourFormData });
    else onAddTour(tourFormData);
    setTourFormData({ name: '', driveLink: '', description: '', price: '', bookingNumber: '', imageUrl: '', categories: [] });
    setIsAddingTour(false);
    setEditingTour(null);
  };

  const startEdit = (t: Tour) => {
    setEditingTour(t);
    setTourFormData({
      name: t.name,
      driveLink: t.driveLink,
      description: t.description,
      price: t.price,
      bookingNumber: t.bookingNumber,
      imageUrl: t.imageUrl,
      categories: Array.isArray(t.categories) ? t.categories : []
    });
    setIsAddingTour(true);
  };

  return (
    <div className="space-y-10 pb-20 animate-fade-in px-4 md:px-0">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-[1000] text-slate-900 tracking-tighter">ম্যানেজমেন্ট হাব</h2>
          <p className="text-slate-400 text-sm font-bold uppercase tracking-widest mt-1">PTT Dashboard</p>
        </div>
        <div className="flex bg-slate-100 p-1.5 rounded-2xl w-full md:w-auto">
          <button onClick={() => setActiveTab('tours')} className={`flex-1 md:px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'tours' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>ট্যুর প্যাকেজ</button>
          <button onClick={() => setActiveTab('users')} className={`flex-1 md:px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>টিম মেম্বারস</button>
        </div>
      </header>

      {activeTab === 'tours' && (
        <div className="space-y-8">
          <div className="flex justify-end">
            {!isAddingTour && (
              <button onClick={() => setIsAddingTour(true)} className="btn-gradient px-8 py-4 rounded-2xl text-xs font-black shadow-xl flex items-center gap-2"><Plus size={18} /> নতুন ট্যুর যোগ করুন</button>
            )}
          </div>

          {isAddingTour && (
            <div className="bg-white p-8 md:p-12 rounded-[2.5rem] border border-slate-100 shadow-2xl animate-in zoom-in-95 duration-500">
               <div className="flex justify-between items-center mb-10">
                 <h3 className="text-2xl font-black text-slate-900 tracking-tight">{editingTour ? 'প্যাকেজ এডিট করুন' : 'নতুন প্যাকেজ তৈরি'}</h3>
                 <button onClick={() => {setIsAddingTour(false); setEditingTour(null); setTourFormData({name:'', driveLink:'', description:'', price:'', bookingNumber:'', imageUrl:'', categories:[]});}} className="p-3 text-slate-300 hover:text-slate-900 transition-colors"><X size={24} /></button>
               </div>
               <form onSubmit={handleTourSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
                 <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">ট্যুরের নাম</label>
                   <input required value={tourFormData.name} onChange={(e) => setTourFormData({...tourFormData, name: e.target.value})} className="w-full bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none focus:ring-4 focus:ring-indigo-500/5 transition-all bengali-text" placeholder="যেমন: সাজেক ভ্যালি" />
                 </div>

                 <div className="space-y-4 md:col-span-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">ক্যাটাগরি সিলেক্ট করুন (একাধিক হতে পারে)</label>
                   <div className="flex flex-wrap gap-2">
                     {availableCategories.map(cat => {
                       const isSelected = tourFormData.categories.includes(cat);
                       return (
                         <button
                           key={cat}
                           type="button"
                           onClick={() => toggleCategory(cat)}
                           className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all flex items-center gap-2 ${isSelected ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                         >
                           {isSelected && <Check size={12} />}
                           {cat}
                         </button>
                       );
                     })}
                   </div>
                 </div>

                 <input required value={tourFormData.price} onChange={(e) => setTourFormData({...tourFormData, price: e.target.value})} placeholder="প্যাকেজ মূল্য (৳)" className="bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none" />
                 <input required value={tourFormData.bookingNumber} onChange={(e) => setTourFormData({...tourFormData, bookingNumber: e.target.value})} placeholder="বুকিং নম্বর" className="bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none" />
                 <div className="md:col-span-2"><input value={tourFormData.imageUrl} onChange={(e) => setTourFormData({...tourFormData, imageUrl: e.target.value})} placeholder="ছবির ইউআরএল (যেমন: https://...)" className="w-full bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none" /></div>
                 <div className="md:col-span-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4 mb-2 block">বিস্তারিত বর্ণনা (লাইন ব্রেক কাজ করবে)</label>
                   <textarea required rows={8} value={tourFormData.description} onChange={(e) => setTourFormData({...tourFormData, description: e.target.value})} placeholder="বিস্তারিত বর্ণনা লিখুন। এন্টার চেপে নতুন লাইন শুরু করুন..." className="w-full bg-slate-50 px-6 py-4 rounded-2xl font-bold outline-none bengali-text"></textarea>
                 </div>
                 <button type="submit" className="md:col-span-2 btn-gradient py-5 rounded-2xl font-black text-sm shadow-xl active:scale-95 transition-all">সবকিছু সেভ করুন</button>
               </form>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {tours.map(t => (
              <div key={t.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 group shadow-sm">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <div className="flex flex-wrap gap-1">
                      {(t.categories || []).slice(0, 2).map(cat => (
                         <span key={cat} className="text-[8px] font-black text-indigo-500 uppercase tracking-widest bg-indigo-50 px-1.5 py-0.5 rounded-md">{cat}</span>
                      ))}
                      {(t.categories || []).length > 2 && <span className="text-[8px] font-black text-indigo-500 uppercase tracking-widest bg-indigo-50 px-1.5 py-0.5 rounded-md">+{(t.categories || []).length - 2}</span>}
                    </div>
                    <h4 className="text-lg font-black text-slate-900 tracking-tight leading-none mt-1 bengali-text">{t.name}</h4>
                  </div>
                  <div className="flex gap-1">
                    <button onClick={() => startEdit(t)} className="p-2 text-slate-300 hover:text-indigo-600 transition-colors"><Edit size={18} /></button>
                    <button onClick={() => onDeleteTour(t.id)} className="p-2 text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                  </div>
                </div>
                <p className="text-lg font-black text-slate-900 tracking-tighter">৳{t.price}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'users' && (
        <div className="bg-white rounded-[2.5rem] overflow-hidden border border-slate-50 shadow-sm overflow-x-auto">
          <table className="w-full text-left min-w-[600px]">
            <thead className="bg-slate-50/50">
              <tr>
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">নাম ও ইমেইল</th>
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">স্ট্যাটাস</th>
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">রোল সিলেক্ট</th>
                <th className="px-10 py-6 text-right"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {users.map(u => (
                <tr key={u.id} className="hover:bg-slate-50/30 transition-all">
                  <td className="px-10 py-6">
                    <p className="font-black text-slate-900">{u.name}</p>
                    <p className="text-[11px] text-slate-400 font-medium">{u.email}</p>
                  </td>
                  <td className="px-10 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${u.isApproved ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                      {u.isApproved ? 'Active' : 'Pending'}
