                  <td className="px-10 py-6">
                    <select value={u.role} onChange={(e) => onApproveUser(u.id, e.target.value as UserRole)} className="bg-slate-100 px-4 py-2 rounded-xl text-[10px] font-black outline-none border-none">
                      <option value={UserRole.GUEST}>গেস্ট</option>
                      <option value={UserRole.MODERATOR}>মডারেটর</option>
                      <option value={UserRole.ADMIN}>এডমিন</option>
                    </select>
                  </td>
                  <td className="px-10 py-6 text-right">
                    <button onClick={() => onDeleteUser(u.id)} className="p-3 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 size={20} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

