const CACHE_NAME = 'ptt-v8';
const ASSETS_TO_CACHE = [
  './',
  './index.html',
  './manifest.json',
  'https://i.postimg.cc/xj3Bb7TR/Untitled_design.png'
];

self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS_TO_CACHE);
    })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((name) => {
          if (name !== CACHE_NAME) {
            return caches.delete(name);
          }
        })
      );
    })
  );
  self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // Bypass Firebase and Google APIs - let them handle their own networking/cache
  if (url.hostname.includes('firebase') || url.hostname.includes('googleapis')) {
    return;
  }

  if (event.request.method !== 'GET') return;

  // Handle navigation requests - always serve index.html for client-side routing
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request).catch(() => {
        return caches.match('./index.html') || caches.match('./');
      })
    );
    return;
  }

  // Network falling back to cache
  event.respondWith(
    fetch(event.request).catch(() => {
      return caches.match(event.request);
    })
  );
});

import { GoogleGenAI } from "@google/genai";

export type CaptionSize = 'small' | 'medium' | 'large';

/**
 * Calculates the date for Thursday of the current week in Bengali format.
 */
function getTargetThursdayDate(): string {
  const months = ['জানুয়ারি', 'ফেব্রুয়ারি', 'মার্চ', 'এপ্রিল', 'মে', 'জুন', 'জুলাই', 'আগস্ট', 'সেপ্টেম্বর', 'অক্টোবর', 'নভেম্বর', 'ডিসেম্বর'];
  const bengaliDigits: Record<string, string> = {
    '0': '০', '1': '১', '2': '২', '3': '৩', '4': '৪', '5': '৫', '6': '৬', '7': '৭', '8': '৮', '9': '৯'
  };

  const toBengaliNumber = (num: number) => num.toString().split('').map(d => bengaliDigits[d] || d).join('');

  const today = new Date();
  const currentDay = today.getDay(); 

  if (currentDay === 4) {
    return "আজই";
  }

  const diff = 4 - currentDay;
  const targetDate = new Date(today);
  targetDate.setDate(today.getDate() + (diff < 0 ? diff + 7 : diff));

  const dateNum = targetDate.getDate();
  const monthName = months[targetDate.getMonth()];

  return `${toBengaliNumber(dateNum)} ই ${monthName} বৃহস্পতিবার`;
}

/**
 * Generates factual yet soulful human-like travel captions using the Gemini API.
 */
export async function generateCaptions(
  description: string, 
  price: string, 
  bookingNumber: string, 
  tourName: string,
  size: CaptionSize
): Promise<string> {

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const thursdayText = getTargetThursdayDate();

  const lengthGuideline = {
    small: "১-২ লাইন। শুধু মূল আকর্ষণ আর দাম।",
    medium: "৩-৪ লাইন। বিশেষত্ব আর বুকিং তথ্য।",
    large: "৫-৭ লাইন। কাব্যিক ও বিস্তারিত।"
  }[size];

  const contactBlock = `বিস্তারিত যোগাযোগ:
01305497151 — Md. Sohedul Islam (Founder & Admin)
01314083035 — MD Salauddin (Admin)
01757078716 — Abu Saleh Ahmed (Admin)`;

  const prompt = `Create a short, natural Bengali travel post for "${tourName}".
  Details: ${description}
  Price: ৳${price}
  Deadline: ${thursdayText}
  Length: ${lengthGuideline}
  Style: Human, soulful, avoid corporate jargon. Use চলিত ভাষা.

  End with EXACTLY:
  ${contactBlock}`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        temperature: 0.7,
        topP: 0.8,
        maxOutputTokens: 500
      }
    });

    return response.text?.trim() || "দুঃখিত, ক্যাপশন তৈরি করা সম্ভব হয়নি।";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "দুঃখিত, এই মুহূর্তে ক্যাপশন তৈরি করা সম্ভব হচ্ছে না।";
  }
}

