import { GoogleGenAI } from "@google/genai";

export type CaptionSize = 'small' | 'medium' | 'large';

/**
 * Calculates the date for Thursday of the current week in Bengali format.
 */
function getTargetThursdayDate(): string {
  const months = ['জানুয়ারি', 'ফেব্রুয়ারি', 'মার্চ', 'এপ্রিল', 'মে', 'জুন', 'জুলাই', 'আগস্ট', 'সেপ্টেম্বর', 'অক্টোবর', 'নভেম্বর', 'ডিসেম্বর'];
  const bengaliDigits: Record<string, string> = {
    '0': '০', '1': '১', '2': '২', '3': '৩', '4': '৪', '5': '৫', '6': '৬', '7': '৭', '8': '৮', '9': '৯'
  };

  const toBengaliNumber = (num: number) => num.toString().split('').map(d => bengaliDigits[d] || d).join('');

  const today = new Date();
  const currentDay = today.getDay(); 

  // If today is Thursday, show it for next Thursday or just "This Thursday"
  const diff = 4 - currentDay;
  const targetDate = new Date(today);
  targetDate.setDate(today.getDate() + (diff <= 0 ? diff + 7 : diff));

  const dateNum = targetDate.getDate();
  const monthName = months[targetDate.getMonth()];

  return `${toBengaliNumber(dateNum)} ই ${monthName} বৃহস্পতিবার`;
}

/**
 * Generates soulful human-like travel captions using the Gemini API.
 */
export async function generateCaptions(
  description: string, 
  price: string, 
  bookingNumber: string, 
  tourName: string,
  size: CaptionSize
): Promise<string> {

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const thursdayText = getTargetThursdayDate();

  const lengthGuideline = {
    small: "খুবই ছোট (১-২ লাইন)।",
    medium: "মাঝারি (৩-৪ লাইন)।",
    large: "বিস্তারিত (৫-৬ লাইন)।"
  }[size];

  const contactBlock = `বিস্তারিত যোগাযোগ:
01305497151 — Md. Sohedul Islam (Founder & Admin)
01314083035 — MD Salauddin(Admin)
01757078716 — Abu Saleh Ahmed  (Admin)`;

  // Soulful prompt as requested ("ager tai")
  const prompt = `প্যাকেজ: ${tourName}
বিস্তারিত: ${description}
মূল্য: ৳${price}
বুকিং শেষ সময়: ${thursdayText}

একটি সুন্দর এবং কাব্যিক ফেসবুক পোস্ট লিখুন। ভাষা হবে একদম স্বাভাবিক এবং মানুষের মতো (চলিত বাংলা)। 
অতিরিক্ত কর্পোরেট বা রোবোটিক শব্দ এড়িয়ে চলবেন। 
পোস্টের সাইজ হবে: ${lengthGuideline}

শেষে অবশ্যই এই তথ্যগুলো থাকবে:
${contactBlock}`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.8,
        topP: 0.9,
      }
    });

    const textOutput = response.text;
    if (!textOutput) {
      throw new Error("Empty AI response");
    }
    return textOutput.trim();
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "দুঃখিত, ক্যাপশন জেনারেট করা সম্ভব হয়নি। দয়া করে আপনার ইন্টারনেট কানেকশন চেক করে আবার চেষ্টা করুন।";
  }
}

