/**
 * Calculates the date for Thursday of the current week in Bengali format.
 * If today is Thursday, it returns "Today".
 */
function getTargetThursdayDate(): string {
  const months = ['জানুয়ারি', 'ফেব্রুয়ারি', 'মার্চ', 'এপ্রিল', 'মে', 'জুন', 'জুলাই', 'আগস্ট', 'সেপ্টেম্বর', 'অক্টোবর', 'নভেম্বর', 'ডিসেম্বর'];
  const bengaliDigits = ['০', '১', '২', '৩', '৪', '৫', '৬', '৭', '৮', '৯'];

  const toBengaliNumber = (num: number) => {
    return num.toString().split('').map(d => bengaliDigits[parseInt(d)]).join('');
  };

  const today = new Date();
  const currentDay = today.getDay(); // 0 (Sun) to 6 (Sat)

  // If today is Thursday (4)
  if (currentDay === 4) {
    return "আজই (বৃহস্পতিবার)";
  }

  // Calculate difference to get to Thursday of this current week
  // If today is Sun(0), diff is 4. If today is Fri(5), diff is -1 (yesterday).
  const diff = 4 - currentDay;
  const targetDate = new Date(today);
  targetDate.setDate(today.getDate() + diff);

  const dateNum = targetDate.getDate();
  const monthName = months[targetDate.getMonth()];

  return `${toBengaliNumber(dateNum)} ই ${monthName} বৃহস্পতিবার`;
}

